// C2_S3 河流（原7题，追加10题）
window.QB_G8_C2_S3.push(
  {c:'中国',q:'长江流经哪些省级行政区？',o:['6个','9个','11个（青、藏、川、渝、鄂、湘、赣、皖、苏、沪）','13个'],a:2,e:'长江干流流经11个省级行政区：青海、西藏、四川、重庆、湖北、湖南、江西、安徽、江苏、上海（10省市+西藏）。长江上中下游分界城市：宜昌/湖口。'},
  {c:'中国',q:'黄河发源于哪里？最终注入什么海？',o:['青海巴颜喀拉山北麓，注入渤海','西藏唐古拉山，注入东海','祁连山，注入黄海','昆仑山，注入南海'],a:0,e:'黄河发源于青海省巴颜喀拉山北麓约古宗列盆地，干流全长约5464km，自西向东流经9省区，最终在山东东营注入渤海。'},
  {c:'中国',q:'黄河"地上河"带来的主要危害是？',o:['水力发电少','一旦决口泛滥成灾，历史上多次改道，威胁下游人民生命财产安全','导致缺水','使渔业减少'],a:1,e:'黄河地上河高出地面数米，河床持续抬高，一旦堤防决口（夺堤），洪水泛滥危害极大。历史上黄河多次大决口，给华北平原造成巨大损失，有"中国之忧患"之称。'},
  {c:'中国',q:'长江上中下游的分界城市是？',o:['武汉/南京','宜昌/湖口（江西九江）','重庆/武汉','成都/重庆'],a:1,e:'长江分段：①上游：源头→宜昌（多峡谷，落差大，水能丰富；三峡在此）②中游：宜昌→湖口（多曲流，荆江九曲，多湖泊）③下游：湖口→入海（河宽水深，航运便利）。'},
  {c:'中国',q:'三峡水电站建在哪条河流上？主要效益是什么？',o:['黄河，防洪发电','长江（宜昌段），集防洪、发电、航运、供水多项效益','珠江，以航运为主','淮河，以防洪为主'],a:1,e:'三峡水电站位于长江三峡（宜昌），是世界上装机容量最大的水电站（2250万千瓦）。综合效益：防洪（减轻中下游洪灾）+发电（清洁能源）+航运（改善川渝通航条件）。'},
  {c:'中国',q:'中国外流河中，注入印度洋的主要河流是？',o:['长江、黄河','雅鲁藏布江（→布拉马普特拉河→孟加拉湾）和怒江（→萨尔温江）','珠江','辽河'],a:1,e:'注入印度洋的中国河流：①雅鲁藏布江（西藏，流出国境后称布拉马普特拉河，注入孟加拉湾）②怒江（云南，出境后称萨尔温江，注入印度洋）。'},
  {c:'中国',q:'淮河的主要地理意义是？',o:['中国最大的内流河','中国南北方分界线（与秦岭共同构成）的河流部分','中国流量最大的河流','中国最短的河流'],a:1,e:'淮河与秦岭共同构成中国南北方地理分界线（800mm等降水量线、1月0℃等温线、亚热带与暖温带分界）。淮河发源于河南省桐柏山，流入洪泽湖后经多条河道入海/入江。'},
  {c:'中国',q:'珠江是中国南方最大的河流，注入什么海？',o:['黄海','东海','南海','渤海'],a:2,e:'珠江是中国南方最大河流（流量仅次于长江），由西江、北江、东江汇合而成，注入南海。珠三角（广州、深圳、香港附近）是中国最发达的经济区之一。'},
  {c:'中国',q:'中国内流区（不流入海洋的区域）主要在哪里？最大的内流河是？',o:['东部平原；黄河','西北内陆；塔里木河（最长内流河）','东北；黑龙江','西南；雅鲁藏布江'],a:1,e:'内流区主要在西北干旱地区（新疆、甘肃、内蒙古西部），河水注入内陆湖泊或消失在沙漠中。塔里木河是中国最长的内流河（约2437km），流域在新疆塔里木盆地。'},
  {c:'中国',q:'中国水能资源最丰富的地区是？',o:['华北平原','黄土高原','西南地区（青藏高原边缘，长江上游及其支流）','东北平原'],a:2,e:'水能资源公式：水量×落差。西南地区：①长江上游及金沙江、雅鲁藏布江落差巨大②水量充沛，因此水能资源极为丰富。中国已建成的大型水电站多集中在西南。'}
);

