// C3_S1 土地资源（原4题，追加10题）
window.QB_G8_C3_S1.push(
  {c:'中国',q:'中国土地资源的基本国情是？',o:['土地面积小，类型单一','总量大，人均少，类型多样，分布不均','耕地多，人均占有量高','山地少，平原多'],a:1,e:'中国土地基本国情：①总量大（世界第三）②人均少（不足世界平均的1/3）③类型多样（耕地、林地、草地、荒漠等齐全）④各类土地分布不均衡。'},
  {c:'中国',q:'中国草地面积最大的地区是？',o:['东北','华北','西部（内蒙古、新疆、青海、西藏等）','东南'],a:2,e:'中国草地（天然草场）面积约400万平方千米，主要分布在西部：内蒙古草原（温带草原）、新疆草原、青藏高原（高寒草甸）等，是重要的牧业基地。'},
  {c:'中国',q:'水土流失会导致哪些后果？',o:['土地增肥','①土地肥力下降②加速荒漠化③下游河流水库淤积④洪涝灾害加重','增加耕地面积','使气候变得湿润'],a:1,e:'水土流失危害：①表土流失使耕地肥力下降，农业减产②泥沙淤积下游河道、水库、湖泊③洪涝风险增加④生态环境破坏，物种减少。'},
  {c:'中国',q:'中国北方的土地荒漠化主要发生在哪里？原因是？',o:['东部沿海；台风侵蚀','西北干旱地区；气候干旱+过度放牧+滥垦土地','南方丘陵；水土流失','青藏高原；冰川融化'],a:1,e:'荒漠化（土地退化）主要在西北干旱半干旱地区：自然原因（气候干旱，风力强）+人为原因（过度放牧、滥垦土地、乱砍滥伐）。沙尘暴是荒漠化的直观体现。'},
  {c:'中国',q:'合理利用土地资源的措施不包括？',o:['退耕还林还草','实行严格的耕地保护制度','大力开垦荒地湿地扩大耕地','防治土壤污染'],a:2,e:'合理利用土地：①退耕还林还草（治理水土流失和荒漠化）②保护耕地红线③防治土壤污染④土地复垦⑤合理开发建设用地。大规模开垦湿地会破坏生态，不是正确措施。'},
  {c:'中国',q:'中国人均耕地面积与世界平均水平相比？',o:['高于世界平均','与世界平均相当','不足世界平均水平的40%','约是世界平均水平的2倍'],a:2,e:'中国人均耕地约0.08公顷，不足世界平均水平（0.2公顷）的40%，耕地人均占有量极少，这正是实行耕地保护政策（18亿亩红线）的根本原因。'},
  {c:'中国',q:'黑龙江省的土壤以什么为主？为何适合农业？',o:['红壤，酸性适合热带作物','黑土，有机质含量高，肥力强，适合种粮食','黄土，容易水土流失','盐碱土，需要改良'],a:1,e:'东北平原的黑土地（黑土）是世界最肥沃的土壤类型之一，有机质含量高达5-8%（普通土壤约1-2%），耕性好，适合玉米、大豆、水稻生长，是中国的"大粮仓"。'},
  {c:'中国',q:'华北平原存在的土地问题主要是？',o:['水土流失','土地沙化、盐碱化（因地下水位高+蒸发强+不合理灌溉）','土地污染','土地冻结'],a:1,e:'华北平原土地问题：①盐碱化（地下水位高、蒸发旺盛、不合理灌溉导致盐分积累）②部分地区沙化（风沙侵袭）。改良措施：排水洗盐、种耐盐植物、改进灌溉方式。'},
  {c:'中国',q:'红壤主要分布在中国哪个地区？有什么特点？',o:['东北，黑色，肥沃','华南（南方丘陵）；红色，酸性，有机质少，肥力较低','华北，黄色，中等肥力','西北，灰色，盐碱性强'],a:1,e:'红壤主要分布在南方（华南、西南）低丘缓坡地区，因高温多雨淋溶作用强，颜色红棕，酸性，有机质少，肥力较低。可通过增施有机肥、种植绿肥改良。'},
  {c:'中国',q:'"退耕还林还草"政策的主要目的是？',o:['减少粮食生产','把坡度较大、水土流失严重的耕地恢复为林地草地，改善生态环境','增加木材产量','发展林业经济'],a:1,e:'退耕还林还草：把坡度>25°的陡坡耕地和严重沙化耕地退出耕种，恢复植被（林或草）以固土保水、防止水土流失和荒漠化扩大。这是生态保护和可持续发展的重要政策。'}
);

// C3_S2 水资源（原4题，追加10题）
window.QB_G8_C3_S2.push(
  {c:'中国',q:'南水北调东线工程的起点是哪里？',o:['黄河','长江下游扬州（利用京杭大运河输水）','长江中游汉江','三峡水库'],a:1,e:'南水北调东线：从扬州（长江下游）抽水，利用京杭大运河及其平行河道向北输水，最终到达天津。东线工程已于2013年通水。'},
  {c:'中国',q:'南水北调中线的起点和终点是？',o:['黄河郑州→北京','丹江口水库（湖北）→北京、天津','三峡水库→郑州','洞庭湖→天津'],a:1,e:'南水北调中线：从丹江口水库（汉江支流，湖北/河南边界）引水，沿途经河南、河北，最终到达北京、天津。中线已于2014年通水，供水效益显著。'},
  {c:'中国',q:'中国人均水资源量与世界平均相比？',o:['高于世界平均','约是世界平均的1/4（严重缺水国家之一）','与世界平均相当','是世界平均的2倍'],a:1,e:'中国水资源总量约2.8万亿m³，居世界第六，但人均仅约2200m³，约为世界平均的1/4，属严重缺水国家（世界水资源紧张警戒线1700m³/人）。'},
  {c:'中国',q:'中国缺水最严重的地区是？',o:['南方水网地区','华北平原和西北干旱区（尤其华北）','东北地区','东南沿海'],a:1,e:'华北缺水：降水少（400-600mm）＋农业和工业用水量大＋人口密集＋地下水过度开采（华北地下水漏斗）。北京、天津、河北等地长期面临水资源短缺问题。'},
  {c:'中国',q:'农业节水的主要方法有哪些？',o:['只能减少种植面积','推广滴灌、喷灌技术；调整作物种植结构；减少大水漫灌','只靠降雨自然节水','增加化肥使用'],a:1,e:'农业节水措施：①推广节水灌溉（滴灌、喷灌比漫灌节水50-80%）②改造渠道防渗漏③调整农业结构（干旱区少种耗水多的水稻）④推广耐旱品种。'},
  {c:'中国',q:'"水价改革"在节约用水中的作用是？',o:['提高水价会增加农民负担，不合适','合理的水价能体现水的稀缺性，促使用水者节约用水，引导合理用水','降低水价才能节约用水','水价与节水无关'],a:1,e:'合理水价（用水越多价格越高的阶梯水价）是经济杠杆，能促进节约用水。免费或低价供水会导致浪费，提高价格（在合理范围内）能有效减少水资源浪费。'},
  {c:'中国',q:'跨流域调水工程（南水北调）能彻底解决北方缺水问题吗？',o:['能，调水来了就完全够用','不能，调水只是补充，还需节水、治水、开源节流综合施策','不能，工程代价太大不划算','能，只需建更多调水工程'],a:0,e:'调水工程是重要补充，但不能根本解决缺水问题。还需：①节约用水（最根本）②提高用水效率③加强水污染治理④海水淡化⑤雨水收集。综合施策才能持续解决缺水问题。'},
  {c:'中国',q:'水污染对水资源利用有什么影响？',o:['没有影响','使可用水资源减少（污染水不能直接使用），加剧水资源紧张','使水资源增多','改善水质'],a:1,e:'水污染（工业废水、农业面源污染、生活污水）使水体丧失使用价值，本已稀缺的可用水资源进一步减少。中国部分河流、地下水污染严重，治理水污染是解决缺水的重要途径。'},
  {c:'中国',q:'世界上最长的人工运河——京杭大运河在南水北调中有什么作用？',o:['无任何作用','东线南水北调工程利用京杭大运河作为主要输水河道','中线利用京杭大运河','西线利用京杭大运河'],a:1,e:'南水北调东线利用了京杭大运河（中国古代最长人工运河，连接北京与杭州，全长约1794km）及其平行河道作为输水通道，大大降低了东线工程建设成本。'},
  {c:'中国',q:'解决中国水资源时间分配不均的措施主要是？',o:['大量抽取地下水','修建水库（调节丰枯水期水量，起到"蓄水"作用）','大量种树','减少工业用水'],a:1,e:'修建水库是解决水资源时间分配不均（丰水期多、枯水期少）的主要工程措施：丰水期蓄水，枯水期放水，实现水资源的季节调配。三峡、小浪底等都有防洪蓄水功能。'}
);

// C3_S3 矿产资源（原3题，追加10题）
window.QB_G8_C3_S3.push(
  {c:'中国',q:'中国稀土资源储量居世界第几位？有何战略意义？',o:['第三，一般性矿产','第一（约占全球36%），是高科技产业必需原料，具有重要战略意义','第二，主要用于建筑','第五，国际竞争力一般'],a:1,e:'中国稀土储量居世界第一，稀土是制造芯片、新能源汽车电池、高性能磁铁、航空航天材料等的关键原料，被称为"工业维生素"，具有极其重要的战略和经济意义。'},
  {c:'中国',q:'中国最大的铁矿区是？',o:['辽宁鞍山','河北唐山','四川攀枝花','内蒙古包头'],a:0,e:'辽宁鞍山是中国最大的铁矿区（鞍山-本溪矿区），鞍钢是中国历史最悠久的大型钢铁企业之一。此外四川攀枝花也是重要的铁矿和钢铁基地。'},
  {c:'中国',q:'中国的非可再生资源和可再生资源分别有哪些例子？',o:['煤炭是可再生的，太阳能是非可再生的','煤炭、石油、天然气是非可再生资源；太阳能、水能、风能是可再生资源','所有矿产资源都可以再生','地下水是非可再生资源'],a:1,e:'非可再生资源：矿产资源（煤、石油、天然气、铁矿、铜矿等），一旦开采消耗难以再生；可再生资源：太阳能、风能、水能、生物质能，可以循环利用，是未来能源的方向。'},
  {c:'中国',q:'中国天然气资源最丰富的地区是？',o:['华北平原','东北平原','西部（四川盆地、新疆塔里木、西藏）和近海','东南沿海'],a:2,e:'中国天然气主要产区：四川盆地（最早开发，产量大）、新疆塔里木（储量巨大，西气东输起点）、鄂尔多斯盆地（陕甘宁）以及渤海、南海近海区域。'},
  {c:'中国',q:'我国矿产资源利用中存在的主要问题是？',o:['矿产资源太多用不完','资源浪费严重（采富弃贫）、综合利用率低、环境破坏大、部分资源短缺','矿产品质太差无法利用','开采技术落后根本无法开采'],a:1,e:'矿产资源利用问题：①开采中"采富弃贫"（只采品位高的，低品位的浪费）②综合利用率低（多种矿物共生，只取一种其他浪费）③矿区环境污染严重④部分重要矿产（如铜、铬）储量不足。'},
  {c:'中国',q:'中国最大的油田是？',o:['新疆克拉玛依油田','山东胜利油田','黑龙江大庆油田','渤海油田'],a:2,e:'大庆油田（黑龙江省）是中国最大、也是世界级特大型油田，1960年代开始大规模开采，"工业学大庆"是著名的历史口号。目前产量有所下降但仍是重要油田。'},
  {c:'中国',q:'页岩气是什么能源？中国储量如何？',o:['传统天然气的一种，储量极少','非常规天然气（储存在页岩层中），中国储量居世界前列（约可开采25万亿立方米）','石油的另一种名称','煤层气的同义词'],a:1,e:'页岩气是储存在致密页岩层中的天然气，需要水力压裂（"压裂"）技术开采。中国页岩气资源量巨大（四川盆地为主），是重要的未来清洁能源。'},
  {c:'中国',q:'合理开发和保护矿产资源的措施有哪些？',o:['尽快全部开采完','提高资源综合利用率、厉行节约、开发替代资源、加强矿区生态保护','禁止开采所有矿产','只开采外国矿产'],a:1,e:'矿产资源保护：①提高采矿综合回收率（减少浪费）②节约使用，提高利用效率③开发矿产替代品和新能源④加强矿区生态修复⑤参与国际资源合作（进口部分矿产）。'},
  {c:'中国',q:'煤炭作为传统能源，其使用对环境有什么主要影响？',o:['完全没有污染','燃烧产生CO₂（温室效应）、SO₂（酸雨）、PM2.5（雾霾），对大气污染严重','只产生CO₂一种问题','开采时才有环境问题，燃烧无影响'],a:1,e:'煤炭燃烧产生：①CO₂加剧温室效应（气候变暖）②SO₂和氮氧化物导致酸雨③粉尘和PM2.5造成雾霾（大气污染）。这是中国推进清洁能源替代的重要原因。'},
  {c:'中国',q:'"西气东输"工程的起点和终点是？',o:['上海到北京','新疆塔里木（轮南）到上海','四川到北京','内蒙古到广州'],a:1,e:'西气东输一线：新疆轮南→上海，全长约4200km，将新疆（西北）丰富的天然气资源输送到东部沿海缺能地区。二线延伸到广州，西气东输三线也已建成。'}
);

// C3_S4 海洋资源（原3题，追加10题）
window.QB_G8_C3_S4.push(
  {c:'中国',q:'舟山渔场是中国最大渔场，其形成原因是？',o:['人工养殖发达','寒暖流交汇+长江带来丰富营养物质+大陆架宽浅，鱼类饵料丰富','海水温度最适合','政府政策扶持'],a:1,e:'舟山渔场（东海）：①台湾暖流和沿岸冷流交汇，鱼类汇聚②长江带来大量有机物（饵料）③大陆架浅（阳光可到海底，利于浮游生物生长）。'},
  {c:'中国',q:'中国的"专属经济区（EEZ）"是从海岸基线起多少海里？有哪些权益？',o:['12海里，领土主权','200海里，对海洋资源（渔业、油气、矿产）享有勘探开发权','500海里，公海权利','100海里，渔业专属权'],a:1,e:'专属经济区（EEZ）：从海岸基线起200海里（约370km），在此范围内，沿海国对自然资源（油气、渔业）有勘探、开发、保护和管理的专属权利，但不影响他国航行权。'},
  {c:'中国',q:'南海在中国海洋权益中的重要性体现在哪些方面？',o:['只有旅游价值','战略地位重要（世界重要航线必经）、油气资源丰富、渔业资源丰富、岛礁众多','只有渔业价值','只有军事价值'],a:1,e:'南海战略意义：①世界最繁忙的航运通道之一（过境货物约占全球贸易30%）②丰富的油气资源（约300亿吨储量）③渔业资源④南沙、西沙、东沙等岛礁是中国领土。'},
  {c:'中国',q:'中国红树林（mangrove）主要分布在哪里？有什么生态价值？',o:['北方海岸','南方热带亚热带沿海（广东、广西、海南、福建）；防浪护岸+碳汇+动物栖息地','东北海岸','内陆湖泊'],a:1,e:'红树林分布在热带亚热带淤泥质海岸，广东、广西、海南等地为主。生态价值：①防浪护岸（"海岸卫士"）②吸碳固碳（碳汇）③鱼虾鸟类重要栖息地④净化水质。'},
  {c:'中国',q:'海水淡化技术对中国有什么意义？',o:['意义不大，中国水资源充足','是解决沿海缺水地区水资源短缺的重要途径，已在天津、浙江舟山等地规模化应用','技术不成熟无法使用','成本太高永远不经济'],a:1,e:'海水淡化（将海水转化为淡水）是解决沿海缺水的重要途径。中国已在天津（北疆电厂）、河北曹妃甸等地建设大型海水淡化工厂，随技术进步成本持续下降。'},
  {c:'中国',q:'中国"蓝色经济"（Blue Economy）的内容包括哪些？',o:['只有捕鱼','海洋捕捞、海水养殖、海洋油气、海洋交通运输、滨海旅游、海洋生物医药等多个产业','只有港口建设','只有近海石油开采'],a:1,e:'蓝色经济涵盖：①海洋渔业（捕捞+养殖）②海洋矿产（油气、海砂）③海洋交通运输（港口+航运）④滨海旅游⑤海洋生物医药⑥海水综合利用⑦海上风电等。'},
  {c:'中国',q:'近年来全球海平面上升对中国沿海地区有什么影响？',o:['有利无害','低地（三角洲）被淹没、咸水入侵、沿海城市洪涝风险增加、岛礁消失威胁','只影响南极地区','使中国沿海地区降水减少'],a:1,e:'海平面上升（全球变暖导致冰川融化+海水热膨胀）对中国的影响：①长三角、珠三角等低洼三角洲面临淹没风险②沿海湿地减少③地下水咸化④极端天气（台风、风暴潮）影响加剧。'},
  {c:'中国',q:'中国对南海的主权主张依据是什么？（历史和法律方面）',o:['完全没有依据','中国对南海拥有历史性权利（中国渔民长期在此作业，历史地图记录），以及岛礁建设后的主权主张','只有军事力量支撑','国际法庭已确认中国拥有全部南海主权'],a:1,e:'中国主张对南海传统渔区及南沙、西沙、中沙、东沙群岛的主权，依据包括：历史性权利（中国古代文献和地图记载）、长期行政管辖、渔民作业历史等。这一问题至今存在国际争议。'},
  {c:'中国',q:'渤海的重要经济价值有哪些？',o:['无经济价值','重要渔场（渤海渔场）、石油天然气资源（胜利油田等）、重要港口（天津、大连）、盐业生产','只有盐业价值','只有军事价值'],a:1,e:'渤海经济价值：①渤海渔场（渤海鱼类、贝类丰富）②丰富油气（胜利油田、大港油田等）③天津、大连、秦皇岛等重要港口④长芦盐场（中国最大盐场）。'},
  {c:'中国',q:'中国伏季休渔制度是什么？有何意义？',o:['冬季禁止渔业活动','每年夏季（5-9月前后）禁止在规定海域捕鱼，让鱼类资源休养生息','全年任意时间段禁渔','只针对外国渔船'],a:1,e:'伏季休渔（约每年5月初至9月初）：在规定海域禁止捕捞，保护鱼类繁殖和生长。意义：①恢复鱼类资源（可持续渔业）②保护海洋生态系统③长远保障渔业产量。'}
);

