// 八上·第四章 中国的经济发展
// ─────────────────────────────────────────────

// C4_S1 农业（原5题，追加10题）
window.QB_G8_C4_S1.push(
  {c:'中国',q:'中国农业生产的四大部门是？',o:['种植业、林业、牧业、渔业','种植业、工业、服务业、交通业','农业、工业、建筑业、商业','粮食、经济作物、蔬菜、水果'],a:0,e:'农业四大部门：①种植业（农作物）②林业（木材、经济林）③牧业（牲畜，主要在西部草原）④渔业（海洋捕捞和淡水养殖）。广义农业包括这四个部门。'},
  {c:'中国',q:'我国经济作物主要有哪些？主要分布在哪里？',o:['只有棉花','棉花（新疆、华北）、甘蔗（南方）、甜菜（北方）、油菜（长江流域）、花生（华北）等，南北皆有','只有甘蔗（南方）','全部在沿海'],a:1,e:'主要经济作物及分布：棉花（新疆、华北最多）、甘蔗（广东、广西、云南，南方）、甜菜（内蒙古、黑龙江，北方）、油菜（长江流域最多）、花生（山东、广东）。'},
  {c:'中国',q:'中国粮食安全面临的主要挑战是？',o:['粮食产量严重过剩','耕地持续减少、人口增长、水资源不足、气候变化等威胁粮食生产','粮食全靠进口','农业劳动力过多'],a:1,e:'粮食安全挑战：①耕地减少（城镇化侵占）②人口增加（需求上升）③水资源短缺影响灌溉④气候变化带来极端天气⑤农业劳动力老龄化⑥种子技术竞争。中国坚持"藏粮于地、藏粮于技"战略。'},
  {c:'中国',q:'农业现代化的主要标志是什么？',o:['只看粮食产量','机械化程度高、科技水平先进（良种、化肥、农药）、劳动生产率高、商品化程度高','劳动力数量多','农村人口比例高'],a:1,e:'农业现代化标志：①机械化（大型农机替代人力）②科技化（基因工程良种、精准农业）③商品化（农产品进入市场流通）④规模化（适度规模经营）⑤生态化（绿色农业）。'},
  {c:'中国',q:'茶叶主要产于中国哪些地区？',o:['北方（东北、华北）','南方丘陵（浙江、福建、云南、四川、安徽等地），喜温暖湿润气候','西北干旱地区','东北冷凉地区'],a:1,e:'茶叶喜温暖湿润、排水良好的酸性土壤（红壤），主产于南方：浙江（龙井）、福建（铁观音、大红袍）、云南（普洱茶）、安徽（黄山毛峰）、四川（蒙顶茶）。'},
  {c:'中国',q:'海南岛和云南南部能种植橡胶、椰子等热带作物，原因是？',o:['土地肥沃','纬度低，气温高，属热带季风气候，全年高温，适合热带作物生长','降水量最多','政府政策扶持'],a:1,e:'海南岛和云南南部（西双版纳等）位于北纬20°以南，属热带季风气候，全年气温高，无霜期长（或无霜），可以种植橡胶、椰子、香蕉、甘蔗、咖啡等热带经济作物。'},
  {c:'中国',q:'我国农业发展的方向是？',o:['继续扩大耕地面积','建设高标准农田、发展农业科技、推进农业绿色发展、推进农业现代化','减少农业投入依靠进口','只发展精品农业放弃大宗粮食'],a:1,e:'农业发展方向：①建设高标准农田（提高单产）②科技兴农（良种、精准农业）③绿色农业（减少化肥农药污染）④农业机械化⑤三产融合（农业+旅游+加工）⑥保护耕地红线。'},
  {c:'中国',q:'中国大豆（黄豆）的主产区是？',o:['南方（广东、广西）','东北地区（黑龙江为主）和华北','西北干旱区','青藏高原'],a:1,e:'大豆主产区：黑龙江、内蒙古（东北为主，占全国产量70%以上）以及河南、安徽等华北地区。中国大豆进口量巨大（主要来自巴西、美国、阿根廷），大豆自给率不高。'},
  {c:'中国',q:'农业区位因素包括哪些？（地理因素分类）',o:['只有气候','气候（温度、降水）、地形（坡度）、土壤、水源、市场、劳动力、政策、技术等','只有土壤','只有政策'],a:1,e:'农业区位因素：自然因素（气候、地形、土壤、水源）和社会经济因素（市场需求、劳动力、交通、技术、政策）。自然因素决定农业类型，社会经济因素影响农业发展。'},
  {c:'中国',q:'中国农村的"家庭联产承包责任制"改革的主要内容是？',o:['农村土地私有化','土地所有权归集体，农民获得土地使用经营权（承包权），可以自主经营、按市场卖产品','全部土地收归国有','农民不再种地全部进城'],a:1,e:'家庭联产承包责任制（1978年后推行）：土地所有权仍归集体（村集体），农民通过承包获得经营使用权，超额产品归自己，大大激发了农民生产积极性，农业产量显著提高。'}
);

// C4_S2 工业（原4题，追加10题）
window.QB_G8_C4_S2.push(
  {c:'中国',q:'中国四大工业基地各自的主要特点是？',o:['都是以轻工业为主','辽中南：重工业；京津唐：重工业+高科技；长三角：门类最全最大；珠三角：轻工业+外向型','都以高科技为主','都是以纺织业为主'],a:1,e:'四大工业基地：①辽中南（鞍山、沈阳）：老工业基地，重工业（钢铁机械）为主②京津唐：钢铁+机械+化工+电子③长三角（上海中心）：最大，门类最全，技术水平最高④珠三角：轻工业+外向型出口。'},
  {c:'中国',q:'长三角地区发展工业的优越条件有哪些？',o:['煤铁资源丰富','地理位置优越（沿海+长江出海口）、交通便利、劳动力充足、技术水平高、市场广阔、历史工业基础好','远离市场','劳动力成本低'],a:1,e:'长三角区位优势：①沿海+长江入海口，水运极便利②邻近资源产地（内地）③资金技术雄厚（外资+本土）④劳动力充足且素质较高⑤市场广阔（国内+出口）⑥历史上开发早，工业基础好。'},
  {c:'中国',q:'中国改革开放后，最早设立的四个经济特区是？',o:['上海、北京、广州、深圳','深圳、珠海、汕头、厦门','深圳、珠海、上海、大连','广州、深圳、珠海、福州'],a:1,e:'1980年设立的四个经济特区：深圳（广东）、珠海（广东）、汕头（广东）、厦门（福建）。经济特区享有特殊优惠政策，吸引外资，是改革开放的"试验田"。'},
  {c:'中国',q:'中国工业向西部转移的主要原因是？',o:['西部劳动力技术水平更高','西部有丰富的资源和廉价劳动力，东部成本上升，国家鼓励西部开发','东部产业已全部消失','政府强制要求'],a:1,e:'产业向西转移：①东部土地和劳动力成本上升②西部劳动力充足且成本较低③西部矿产、能源资源丰富④西部大开发政策鼓励（税收优惠、基础设施建设）。'},
  {c:'中国',q:'珠三角工业发展的有利条件是？',o:['煤铁资源丰富','毗邻港澳，对外开放早，吸引大量外资；劳动力充足，海运便利','科技水平全国最高','历史工业基础最雄厚'],a:1,e:'珠三角优势：①毗邻香港，对外开放早（1980年代先行先试）②大量港台和外资流入③劳动力充足（大量内地务工人员）④海运便利（珠江入海，南海航运）⑤政策优惠。'},
  {c:'中国',q:'高新技术产业主要布局在哪些地区？',o:['煤矿附近','大城市及其郊区（北京中关村、上海张江、深圳高新区等），靠近高校和研究机构','农村地区','边疆地区'],a:1,e:'高新技术产业区位因素：①科技人才（靠近高校科研机构）②资金（风险投资集中）③市场信息（大城市）。典型：北京中关村（"中国硅谷"）、上海张江、深圳南山、杭州未来科技城。'},
  {c:'中国',q:'中国制造业的比较优势（相对优势）是什么？',o:['科技水平全球最高','劳动力数量多且成本相对低，产业链完整，基础设施完善','土地资源最充足','资本最为充裕'],a:1,e:'中国制造业优势：①劳动力数量大（随技术进步转向工程师红利）②产业链完整（从原材料到终端产品）③基础设施完善（交通、物流、电力）④政府政策支持⑤市场规模大。'},
  {c:'中国',q:'"中国制造2025"战略的目标是什么？',o:['只做传统制造业','推动中国制造业从大到强转型，重点发展芯片、新能源、航空航天、生物医药等高端制造业','完全放弃制造业发展服务业','引进外资替代本土企业'],a:1,e:'《中国制造2025》（2015年发布）：以创新驱动，推动中国制造业从"制造大国"向"制造强国"转型，重点突破集成电路（芯片）、高端数控机床、新能源汽车等10大领域。'},
  {c:'中国',q:'东北老工业基地衰落的主要原因有哪些？',o:['从未发达过','资源枯竭（煤铁减少）、体制僵化（国企占比高）、产业结构单一（过度依赖重工业）、人才流失','技术太先进导致无人操作','地理位置偏远'],a:1,e:'东北振兴面临的问题：①资源型城市（煤、钢）资源枯竭（如鹤岗、阜新）②计划经济体制惯性强，市场化改革滞后③产业结构单一，转型困难④人才外流（"投奔南方"）⑤冬季严寒限制部分产业。'},
  {c:'中国',q:'中国新能源产业（太阳能、风能）的发展现状是？',o:['刚刚起步，规模很小','风电、光伏装机容量均居世界第一，已成为全球最大新能源生产和消费国','严重依赖进口','技术水平落后于欧美'],a:1,e:'中国新能源成就：风电装机容量全球第一、光伏（太阳能）发电装机全球第一，新能源汽车产销量全球第一。新疆、内蒙古（风能）、西藏、青海（太阳能）是重要能源基地。'}
);

// C4_S3 交通（原5题，追加10题）
window.QB_G8_C4_S3.push(
  {c:'中国',q:'中国高铁网络的"四纵四横"后来升级为"八纵八横"，这对中国经济意义是？',o:['增加了旅游景点','缩短城市间出行时间，促进区域经济一体化，带动沿线地区发展，形成经济走廊','只对旅客有利','使航空和公路运输消失'],a:1,e:'"八纵八横"高铁网使北京到上海4.5小时，北京到广州8小时。意义：①促进区域间要素流动②带动高铁沿线城市发展（"高铁经济"）③减少碳排放（替代飞机短途）④缩小区域差距。'},
  {c:'中国',q:'长江成为"黄金水道"的主要原因是？',o:['水量少，水位稳定','水量大（径流量亚洲第一）、通航里程长、干支流覆盖广、连接东中西部，航运价值极高','全程河道平直','无任何险滩'],a:1,e:'长江"黄金水道"：①年径流量约9600亿m³，水量充沛②可通航里程约6300km③干支流可通达四川、云南等内地④三峡工程后重庆至宜昌可通万吨级船队⑤连接东部出海口与西部腹地。'},
  {c:'中国',q:'青藏铁路（拉萨线）修建面临的主要困难是？',o:['地形太平坦无法修建','海拔高（>4000m）、多年冻土、高寒缺氧、生态脆弱，是世界铁路修建史上最艰难的工程之一','资金不足','技术已经完全成熟无任何困难'],a:1,e:'青藏铁路（格尔木-拉萨，全长1142km）难题：①高原缺氧（列车全程供氧）②多年冻土路基（需架桥或冷却地基）③高寒（最低气温-40℃）④野生动物保护通道设计⑤生态脆弱保护。'},
  {c:'中国',q:'航空运输的主要优势是什么？适合运输哪类货物？',o:['运量大、运费最低','速度最快、不受地形限制；适合高价值、急需、轻量货物（活体器官、芯片、鲜花等）','门到门最方便','最适合大宗货物'],a:1,e:'航空运输：速度最快，不受地形限制，但运费最贵、运量小。适合：高价值（珠宝、芯片）、紧急（医疗器官）、轻量（鲜花、文件）的特殊货物，以及长距离旅客运输。'},
  {c:'中国',q:'互联网+交通（共享单车、网约车、导航APP）对人们出行的影响是？',o:['使交通更拥堵','方便出行（"最后一公里"）、提高交通效率、降低出行成本、减少私家车使用（降低碳排放）','增加交通事故','使公共交通消失'],a:1,e:'互联网交通革命：①共享单车（ofo、美团）解决"最后一公里"②网约车（滴滴）优化出行匹配③高德/百度地图实时导航避堵④货运平台（满帮）提高物流效率。带来便捷，也带来监管挑战。'},
  {c:'中国',q:'我国管道运输主要运输什么？有什么优缺点？',o:['运输固体矿石','主要运输石油、天然气和部分液态化学品；优点：损耗少、连续稳定、安全，缺点：固定线路、灵活性差、建设成本高','运输粮食','运输人员'],a:1,e:'管道运输：将油气（液体或气体）通过管道输送，24小时连续运输，损耗极少，安全性高。缺点：只能运油气液体，线路固定，初期投资大。西气东输、中俄天然气管道是典型案例。'},
  {c:'中国',q:'中国沿海港口中，位于长三角的最大港口是？',o:['大连','天津','上海港（货物吞吐量全球第一）','宁波-舟山港'],a:2,e:'上海港是中国第一大港，连续多年货物吞吐量全球第一，是国际航运中心。宁波-舟山港是货物吞吐量第二大港。广州港和深圳港是华南最重要港口。'},
  {c:'中国',q:'"一带一路"（BRI）倡议对中国交通发展有什么意义？',o:['只修建国内公路','推动中国向西（陆上丝绸之路）和向海（海上丝绸之路）两个方向构建互联互通网络，促进与沿线国家贸易合作','与交通无关','只对贸易有影响'],a:1,e:'"一带一路"（Belt and Road Initiative）：①陆上（丝绸之路经济带）：中欧班列，连接中国与中亚、欧洲②海上（21世纪海上丝绸之路）：沿海港口建设。促进互联互通，扩大贸易。'},
  {c:'中国',q:'中国货运量最大的运输方式是哪个？为什么？',o:['航空','铁路','公路（货运总量第一）','水运（货物周转量大）'],a:2,e:'公路货运量（吨数）第一：因为公路"门到门"灵活，遍及城乡，适合中短途运输。但货物周转量（吨·千米）最大的是水运（海运），因为海运可以长距离运输超大量级货物。'},
  {c:'中国',q:'中欧班列（"义新欧"等）有什么意义？',o:['只是普通铁路货运','连接中国与欧洲的国际铁路货运线路，减少海运时间（约海运的1/3），促进中欧贸易','速度比飞机快','主要运输旅客'],a:1,e:'中欧班列：连接中国（义乌、成都、武汉等）与欧洲（马德里、汉堡、波兰等）的货运列车，2周左右到达（比海运快约1/2）、比空运便宜，带动沿线"一带一路"国家经济。'}
);

