// C7_S1 北方地区概况（原2题，追加10题）
window.QB_G8_C7_S1.push(
  {c:'中国',q:'北方地区的四至范围大致是？',o:['南到南海，北到漠河','南到秦岭-淮河，北到漠河，西到大兴安岭，东到海岸线','南到长江，北到黄河','南到北回归线，北到北极圈'],a:1,e:'北方地区：秦岭-淮河以北，大兴安岭以东，包括东北三省、华北各省（北京、天津、河北、山东、河南等）、山西、陕西北部等。'},
  {c:'中国',q:'华北平原主要由哪几条河流冲积而成？',o:['长江、珠江','黄河、淮河、海河（三条河流共同冲积）','辽河、松花江','汉江、渭河'],a:1,e:'华北平原：由黄河、淮河、海河冲积而成（又称"黄淮海平原"），地势低平（<50m），土地肥沃，是中国重要的粮食产区（小麦、玉米）。'},
  {c:'中国',q:'华北平原冬春季最主要的气象灾害是？',o:['台风','旱灾（春旱）和沙尘暴','洪涝','寒潮冻害'],a:1,e:'华北平原春旱：冬小麦返青时节（3-5月）降水少，气温回升快，蒸发大，旱情严重，对冬小麦生长威胁大。同期还常有沙尘暴侵袭（来自西北）。'},
  {c:'中国',q:'北方地区居民的传统饮食以什么为主？',o:['以大米、米线为主（南方饮食）','以面食（馒头、面条、饺子、包子）为主，因主产小麦','以青稞为主','以荞麦为主'],a:1,e:'北方（小麦产区）传统饮食以面食为主：馒头、饺子（北方特色）、面条（兰州拉面、陕西刀削面）、包子、烙饼等。南方以大米（米饭、米粉、汤圆）为主。'},
  {c:'中国',q:'北方地区最主要的传统建筑风格是？',o:['吊脚楼（南方傣族）','四合院（北京）、窑洞（陕西、山西黄土高原）','蒙古包（内陆草原）','竹楼（云南傣族）'],a:1,e:'北方建筑：①四合院（北京标志性传统民居，封闭型院落，适应寒冷气候）②窑洞（黄土高原，黄土壁保温好）③北方民居墙厚、朝南开窗大（利于采光保暖）。'},
  {c:'中国',q:'关于北方地区水资源，以下说法正确的是？',o:['北方水资源充足，无需节约','北方水资源严重短缺（人均不足南方的1/6），但用水量大（农业灌溉+工业+城市）','北方水资源略少于南方','北方只靠地下水就能满足需要'],a:1,e:'华北缺水是中国最严重的水资源问题之一：①年降水量少（400-600mm）②蒸发量大③农业灌溉用水量大④地下水过度开采（华北平原地面沉降）。南水北调是重要解决途径。'},
  {c:'中国',q:'北方平原的农业特点有哪些？',o:['全年高温多雨，一年三熟','冬小麦、夏玉米（两年三熟或一年两熟），机械化程度高，商品化率较高','全部以旱地耕作为主，只有一年一熟','完全自给自足，商品化率低'],a:1,e:'华北平原农业：①以旱地为主（小麦、玉米、棉花）②一年两熟（冬小麦夏季收割→夏玉米秋季收割）③平原利于机械化（大型农机）④商品化率高（是国家重要商品粮基地）。'},
  {c:'中国',q:'东北三省为什么是中国重要的重工业基地？',o:['劳动力最多','拥有丰富的铁矿（鞍山-本溪）、煤炭（抚顺、鸡西等）资源，又有苏联援建基础，历史上优先发展重工业','距离海洋最近','技术水平最高'],a:1,e:'东北重工业基地形成原因：①资源：铁矿（鞍山）、煤炭（抚顺、双鸭山）、石油（大庆）②历史：日本占领时期建工厂（伪满）③苏联援助（156项重点工程）④新中国优先发展重工业政策。'},
  {c:'中国',q:'北方地区的气候对农业生产的限制主要体现在？',o:['水热都充足，无限制','热量（生长期短，无霜期短）和水资源（降水少，需灌溉）是主要限制因素','只有水资源限制','只有热量限制'],a:1,e:'北方农业限制：①热量：东北无霜期80-180天（较短），只能一年一熟；华北无霜期180-220天，可一年两熟②水资源：华北年降水400-600mm，农业灌溉依赖地下水或引水工程。'},
  {c:'中国',q:'关中平原（渭河平原）是哪个省的核心农业区？历史地位如何？',o:['山西，历史上是盐业中心','陕西，古代"天府之国"（秦汉时期），现为关中-天水经济区核心','河南，古代都城最多','甘肃，是丝绸之路起点'],a:1,e:'关中平原（渭河下游平原）：陕西省的精华农业区，古代被称为"天府之国"（秦汉时期），西安（长安）是13朝古都所在地。都江堰修建前关中是最重要农业区，土地肥沃，灌溉便利。'}
);

// C7_S2 东北三省（原4题，追加10题）
window.QB_G8_C7_S2.push(
  {c:'中国',q:'东北三省被称为"白山黑水"，这两个词分别指什么？',o:['白色的山和黑色的水，无地理意义','白山=长白山（白雪覆盖，主峰白色火山口）；黑水=黑龙江（古称"黑水"，水色较暗）','白山=白头山，黑水=松花江','白山=大兴安岭，黑水=图们江'],a:1,e:'白山黑水：长白山（白山）是朝鲜族圣山，主峰天池（火山口湖）雪峰常年覆盖；黑龙江（黑水）是中俄界河，东北地区母亲河之一。这是描述东北自然地理的经典词汇。'},
  {c:'中国',q:'东北地区的大兴安岭有什么重要的地理意义？',o:['是中国最高的山脉','东北-西南走向，是东北地区的气候、地形、农牧分界线，也是内蒙古高原与松嫩平原的分界','是长江和黄河的分水岭','是中国最长的山脉'],a:1,e:'大兴安岭：①东北-西南走向，是内蒙古高原与东北平原（松嫩平原）的地形分界②年降水400mm线大致沿此分布（东侧湿润，西侧干旱）③是农业（东）与牧业（西）的大致分界④是黑龙江流域与内陆水系分水岭。'},
  {c:'中国',q:'东北平原的三大组成部分是？',o:['关东平原、松嫩平原、三江平原','松嫩平原、辽河平原、三江平原','华北平原、松嫩平原、辽河平原','黑土平原、白浆土平原、棕壤平原'],a:1,e:'东北平原三部分：①松嫩平原（中北部，松花江和嫩江之间）②辽河平原（南部，辽宁省，沈阳附近）③三江平原（东北角，黑龙江、松花江、乌苏里江三江汇合处，著名湿地）。'},
  {c:'中国',q:'三江平原的重要生态价值是？',o:['是中国最大的工业区','是中国最大的湿地之一，拥有丰富的生物多样性和重要的生态调节功能，被称为"北大仓"和"北国湿地明珠"','全部已开垦为耕地','无特殊价值'],a:1,e:'三江平原（黑龙江省）：原为大片沼泽湿地，曾大规模开垦（"北大荒"→"北大仓"）；现已认识到湿地保护的重要性，保留了大量湿地（保护区），是丹顶鹤、东方白鹳等珍稀鸟类栖息地。'},
  {c:'中国',q:'东北工业基地振兴中，主要面临哪些挑战？需要如何解决？',o:['工业刚起步，无基础','资源枯竭+体制僵化+产业单一；需转型发展新兴产业、吸引投资、改革国企、改善营商环境、留住人才','只需增加政府补贴','只需大量进口外国设备'],a:1,e:'振兴东北：①资源枯竭型城市转型（如抚顺：从煤炭城转型旅游、新材料）②淘汰落后产能③发展新兴产业（信息技术、新材料）④改革国企③改善营商环境⑤留住人才（提高待遇、改善生活条件）。'},
  {c:'中国',q:'东北地区的长白山有什么著名的旅游和地理特征？',o:['只是普通山地','是中国著名山脉，主峰白云峰（2691m），顶部天池（火山口湖）是松花江、图们江、鸭绿江的发源地，也是东北地区重要旅游目的地','是中国最高山','在内蒙古'],a:1,e:'长白山：是中朝界山，主峰2749m（白云峰）。顶部天池（火山口湖）海拔2190m，是中国最高的火山湖，也是松花江（图们江支流）的发源地。冬季有著名的温泉和雾凇景观，滑雪旅游发达。'},
  {c:'中国',q:'哈尔滨冬季的著名旅游节是什么？体现了东北什么气候特征？',o:['桂林山水节','冰雪节（哈尔滨国际冰雪节）；体现东北冬季漫长寒冷、降雪丰富的气候特征','西湖荷花节','广州花市节'],a:1,e:'哈尔滨国际冰雪节（每年1月5日开幕）：以精美的冰雕、雪雕和雪地活动吸引国内外游客，是世界四大冰雪节之一，体现了哈尔滨"冰城"特色（冬季-20℃以下，积雪期长达5个月）。'},
  {c:'中国',q:'东北地区的林业资源有什么重要性？现状是？',o:['东北无森林资源','东北（大兴安岭、小兴安岭、长白山）是中国最大的天然林区，提供大量木材，但过度采伐导致森林减少，现已限制砍伐保护生态','完全已被破坏','完全未开发'],a:1,e:'东北三大林区：大兴安岭（兴安落叶松）、小兴安岭（红松）、长白山（多树种混交林），是中国最大的天然林区（"绿色宝库"）。由于过度采伐，现已实施"天然林保护工程"，禁止商业性采伐。'},
  {c:'中国',q:'沈阳作为东北最大城市，是哪类城市？有哪些代表性工业？',o:['以旅游业为主','以重工业为主（机床、飞机制造、冶金、汽车、农机）的东北最大综合性工业城市和区域中心城市','以金融为主','以农业为主'],a:1,e:'沈阳（辽宁省省会）：东北最大城市（人口约900万），是重要的综合性工业基地：机床（沈阳机床）、航空（飞机制造、沈飞）、冶金（东北特钢）、汽车（华晨宝马）等，是东北振兴的龙头城市。'},
  {c:'中国',q:'为什么东北是中国重要的"商品粮基地"？',o:['人口多，需要大量粮食','地广人稀，人均耕地多，黑土肥沃，机械化程度高，粮食总产量大且大量商品外销','只生产水稻','粮食全部自给'],a:1,e:'东北粮食基地优势：①黑土地肥沃②地广人稀（人均耕地远超全国平均）③适合机械化大规模耕作（地势平坦）④水稻（黑龙江五常大米）、玉米、大豆均优质高产。东北输出大量粮食到全国各地。'}
);

// C7_S3 黄土高原（原3题，追加10题）
window.QB_G8_C7_S3.push(
  {c:'中国',q:'黄土高原的范围包括哪些省区？',o:['只有陕西','山西、陕西北部、甘肃东部、宁夏、河南西部等地，以山西、陕西为核心','四川、贵州、云南','河北、北京、天津'],a:1,e:'黄土高原主体：山西全境、陕西北部（关中以北）、甘肃东部、宁夏大部、河南西部小部分。是中华文明（黄河文明）的重要发源地，也是世界上黄土分布面积最广的高原（约63万km²）。'},
  {c:'中国',q:'黄土的特性中，导致水土流失严重的关键因素是？',o:['黄土太硬，不易侵蚀','黄土结构疏松（颗粒细，间隙大），直立性好但极易被水流冲刷侵蚀','黄土中含大量砾石','黄土太湿，防水性强'],a:1,e:'黄土特性：①质地疏松，颗粒细②垂直节理发育（可以形成直立崖面）③富含钙质，遇水易崩塌④渗水性好，表面干旱。正是这种疏松特性使黄土极易被暴雨冲刷，导致水土流失严重。'},
  {c:'中国',q:'黄土高原的地貌按侵蚀程度可分为哪几类？',o:['平原、山地、盆地','塬（保存完整的高平地）、梁（长条状）、峁（圆丘状）、沟（侵蚀沟谷），体现水土流失的不同程度','山地、丘陵、高原','溶洞、石林、峰丛'],a:1,e:'黄土地貌演变：塬（最完整，顶平坡陡）→梁（塬被切割成长条）→峁（梁进一步侵蚀成孤立圆丘）→沟壑（侵蚀沟谷），侵蚀程度逐渐加剧。沟壑纵横是黄土高原最典型的地貌景观。'},
  {c:'中国',q:'黄土高原的窑洞民居有什么特点？为何适合当地？',o:['防潮性好，适合南方湿热气候','挖凿于黄土崖面，冬暖夏凉（黄土导热性差）、节省建材、防风（高原风大），与黄土高原干旱少雨冬冷夏热的气候完美适应','建造速度最快','是世界最豪华的民居'],a:1,e:'窑洞：在直立黄土崖面横向挖掘，黄土是绝佳隔热材料，冬暖夏凉（年温差大达30℃+），防风防沙（黄土高原冬季风大），不需大量建材，与黄土高原半干旱气候高度适配，是黄土高原独特的民居文化。'},
  {c:'中国',q:'黄土高原治理水土流失中，"坝地"（淤地坝）的作用是？',o:['防洪排水','在沟谷中修建坝体，拦截上游泥沙，在坝后逐渐积成肥沃淤泥（坝地），可用于农业种植，一举多得','只是防洪用途','用于发电'],a:1,e:'淤地坝：在沟谷修建拦沙坝，①拦截泥沙（减少入黄泥沙）②坝后积成的淤泥地（坝地）土壤肥沃、灌溉便利，适合耕作③蓄水防洪。是黄土高原水土保持工程措施的核心。'},
  {c:'中国',q:'黄土高原的气候特征是？对农业有什么影响？',o:['全年高温多雨，适合水稻','温带大陆性气候（半干旱）：降水少（400-600mm），集中夏季，气温日较差大，适合旱作农业（小麦、谷子、高粱）','全年干旱，只能放牧','全年多雾，不适合农业'],a:1,e:'黄土高原气候：半干旱，降水400-600mm（集中7-9月），冬冷夏热，日较差大（有利于有机质积累）。适合旱地作物：谷子（小米，"小米加步枪"的小米来自此地）、高粱、荞麦、小麦等。'},
  {c:'中国',q:'中华民族被称为"黄土地文明"，黄土高原与华夏文明有什么历史关系？',o:['与文明没有关系','黄河流域（黄土高原）是中华文明的重要发源地：半坡遗址（西安附近）、大地湾遗址（甘肃）等史前文明遗址均在此；陕西西安（长安）是多个朝代都城','黄土高原太贫瘠，文明起源于他处','文明仅起源于长江流域'],a:1,e:'黄河文明（黄土文明）：黄河中游（黄土高原）是中华文明重要摇篮。仰韶文化（半坡遗址）、龙山文化、周秦汉唐文明均在黄土高原和关中平原发展兴盛。西安（长安）是13朝古都，黄土高原是华夏民族的精神家园。'},
  {c:'中国',q:'煤炭资源丰富是黄土高原经济发展的重要基础，主要分布在哪些省？',o:['只有陕西','山西（最多，储量约占全国1/3，"煤海"省）和陕西、内蒙古南部','只有内蒙古','云贵地区'],a:1,e:'黄土高原地区（尤其山西）是中国最重要的煤炭基地：大同、阳泉、长治、晋城（山西）和榆林（陕西）等地。山西被称为"煤海省"，煤炭储量约占全国1/3，外运煤炭供全国使用。'},
  {c:'中国',q:'黄土高原的大量泥沙进入黄河后，在下游形成了什么地理现象？如何解决？',o:['使下游变成了深水良港','泥沙在下游（华北平原）大量淤积，河床抬高形成"地上河"，有决口洪水泛滥风险；治理：上中游植树造林减沙、修建小浪底等水库拦沙、下游疏浚河道加固大堤','使下游河流清澈','使下游河流水量减少'],a:1,e:'黄土高原→黄河携沙→下游地上河：治理体系：①上中游：植树造林种草（减少水土流失）、修梯田、修淤地坝②中游：小浪底水库拦沙调水（人工塑造水流冲刷泥沙）③下游：加固大堤、疏浚河道。'},
  {c:'中国',q:'黄土高原为什么是我国水土流失最严重的地区？（综合所有因素）',o:['降水最多，所以最严重','自然（黄土疏松+夏季暴雨集中+沟壑地形）+人为（历史上滥垦滥伐滥牧，植被破坏严重）多因素共同作用','只是地形原因','只是人类活动原因'],a:1,e:'水土流失=侵蚀力（降水动力）×可侵蚀性（土壤疏松）×坡度（黄土沟壑地形）-植被保护。黄土高原：①黄土最疏松②夏季暴雨最集中③历史上植被破坏最严重（秦汉以来砍伐耕垦）。四个条件缺一不可，却四者皆重，所以最严重。'}
);

// C7_S4 北京（原3题，追加10题）
window.QB_G8_C7_S4.push(
  {c:'中国',q:'北京的地理位置特征是？',o:['沿海城市','位于华北平原北部边缘，三面环山（北面燕山、西面太行山），一面向平原，地势西北高东南低','平原中心城市','东北角城市'],a:1,e:'北京位于华北平原北端，西靠太行山，北依燕山，地势西北高（山地）东南低（平原），背山面海（渤海）、居中守险，是历史上兵家必争之地，也是都城的理想选址。'},
  {c:'中国',q:'北京的行政区类型是？在全国的定位是什么？',o:['省，普通地方政府','直辖市，是全国政治中心、文化中心、国际交往中心、科技创新中心','省会城市，是东北中心','自治区，特殊政策区'],a:1,e:'北京是中国四个直辖市之一，官方定位：政治中心（党中央、全国人大、国务院所在地）、文化中心（高校科研最多）、国际交往中心、科技创新中心（中关村）。'},
  {c:'中国',q:'北京有哪些重要的对外交通枢纽？',o:['只有铁路','北京首都国际机场+大兴国际机场（航空）；北京站、北京南站（铁路）；多条高速公路（公路）','只有机场','只有公路'],a:1,e:'北京是全国最重要的交通枢纽之一：①首都国际机场（T3，年旅客超8000万）+大兴国际机场（2019年开放）②铁路：多条高铁（京沪、京广、京津等）以北京为起点③多条高速公路辐射全国。'},
  {c:'中国',q:'北京作为文化中心，有哪些全国最高水平的文化教育机构？',o:['全国数量最少','高校（北大、清华等）数量和质量全国第一；国家级博物馆（故宫、国家博物馆等）和艺术机构（国家大剧院等）云集','只有故宫一个文化场所','文化教育不是北京的强项'],a:1,e:'北京文化中心实力：①顶尖高校：北大、清华、北航、北理工、中科院等②国家级机构：国家博物馆、故宫（世界最大宫殿建筑群）、国家大剧院、国家图书馆③外国使馆和国际组织云集（国际交往）。'},
  {c:'中国',q:'北京的城市规划在建设雄安新区后有哪些变化？',o:['北京将消失','疏解非首都功能：将部分政府机构、企业总部、大学迁往雄安新区，减少北京"大城市病"（人口、交通、环境压力）','雄安取代北京成首都','没有任何变化'],a:1,e:'雄安新区（2017年设立，河北）：承接北京非首都功能疏解，缓解北京人口过多（2300万+）、交通拥堵、房价高涨等"大城市病"。是深圳之后最重大的区域发展战略。'},
  {c:'中国',q:'北京周边的长城有哪些著名路段？',o:['只有八达岭一段','八达岭（最著名，最多游客）、慕田峪（原生态较好）、司马台（野长城）、金山岭等','长城只在东北边境','长城只在北京境内'],a:1,e:'北京境内著名长城段：①八达岭（最著名，也是保护最完整、游客最多）②慕田峪（原生态，外国元首多来此参观）③司马台（最险峻，部分为"野长城"）④古北口等。这些都是明长城遗迹。'},
  {c:'中国',q:'北京年降水量的特点及其对城市的影响是？',o:['全年降水均匀，无旱涝问题','年降水约600mm，高度集中在7-8月（约70%），易导致城市内涝；冬春干旱（沙尘暴常见）','全年多雨，水资源充足','降水极少，全年干旱'],a:1,e:'北京降水特点：约600mm/年，夏季（7-8月）暴雨集中，城市排水压力大，近年多次发生严重内涝（2012年7·21特大暴雨，77人遇难）；春季干旱多风沙。建设"海绵城市"是应对措施。'},
  {c:'中国',q:'中关村科技园区对北京经济的意义是？',o:['只是电脑零件市场','中国第一个国家级高新技术开发区，集聚了大量互联网、人工智能、生物医药企业（联想、百度、小米等），是中国创新经济的发动机','只是传统工业区','对经济影响不大'],a:1,e:'中关村科学城（北京）：中国第一个国家级高新技术产业开发区（1988年），集聚了联想、百度、京东、小米、字节跳动等众多科技巨头，有多所顶尖高校和研究所，是中国"硅谷"。'},
  {c:'中国',q:'北京的天安门广场有哪些政治文化意义？',o:['只是一个旅游景点','是中国国家象征的核心广场，毛主席纪念堂、人民英雄纪念碑、人民大会堂、中国国家博物馆围绕其四周，是国家重大政治活动和节庆的举办场所','只是历史遗迹','商业区中心'],a:1,e:'天安门广场：世界最大城市广场之一（44万m²），北面天安门城楼（明清皇城南门，1949年开国大典举行处），南面毛主席纪念堂，东面国家博物馆，西面人民大会堂（全国人大会议举行处）。'},
  {c:'中国',q:'北京的城市问题主要有哪些？政府采取了哪些应对措施？',o:['北京没有城市问题','人口过多（城市病）：交通拥堵、空气污染、房价高涨、水资源紧缺；措施：限行限购、南水北调、疏解非首都功能、建设雄安新区、发展轨道交通','只有交通问题','只有环境问题'],a:1,e:'北京城市病及对策：①人口过多（2300万+）→疏解到雄安②交通拥堵→地铁扩建（20条+线路）+限行限购③空气污染→清洁取暖+淘汰老旧车④水资源紧缺→南水北调中线每年约10亿m³到京。'}
);

// ─────────────────────────────────────────────
// 八下·第八章 南方地区
// ─────────────────────────────────────────────

// C8_S1 南方地区概况（原2题，追加10题）
window.QB_G8_C8_S1.push(
  {c:'中国',q:'南方地区的气候特点是什么？',o:['全年寒冷干燥','亚热带（或热带）季风气候，夏季高温多雨，冬季温暖少雨；降水丰富（>800mm），以水田农业为主','高寒气候，以牧业为主','全年干旱，以旱作为主'],a:1,e:'南方气候：①亚热带季风气候为主（长江流域），热带季风（海南、云南最南端）②夏季高温多雨，冬季温和（最冷月均温>0℃）③年降水>800mm，4-6月梅雨季，7-8月伏旱（长江中下游）。'},
  {c:'中国',q:'南方地区的传统民居有什么特点？为什么这样设计？',o:['墙厚，封闭，保温','轻巧透气（通风散热），屋顶坡度大（利于排水），墙体薄，窗户大（利于采光通风）；适应南方高温多雨气候','与北方民居完全相同','以帐篷为主'],a:1,e:'南方民居适应高温多雨：①墙薄+大窗（通风散热）②屋顶大坡度（利于排雨水）③悬挑（防雨）④架空（防潮，如傣族竹楼、客家围屋）⑤白墙（反射日光，减少热量吸收）。'},
  {c:'中国',q:'南方地区的农业生产以什么为主？一年几熟？',o:['以旱地为主，小麦为主粮，一年一熟','以水田为主，水稻为主粮，长江流域一年两熟，华南一年三熟','以游牧为主','以渔业为主'],a:1,e:'南方农业：①水田（降水充足）②水稻为主粮（"鱼米之乡"）③熟制：长江流域一年两熟（稻-稻或稻-麦），华南（广东、广西）一年三熟（温度高，无霜期长），海南一年可种4-5季。'},
  {c:'中国',q:'南方地区最著名的传统水乡文化城市有哪些？',o:['哈尔滨、沈阳','苏州、杭州（江浙水乡）、绍兴（乌镇、周庄等古镇）','西安、洛阳','成都、重庆（不属水乡）'],a:1,e:'江南水乡：苏州（小桥流水人家，评弹、昆曲）、杭州（西湖，"上有天堂，下有苏杭"）、绍兴（水乡古镇，鲁迅故里）、乌镇、周庄等，以河网纵横、粉墙黛瓦、古镇文化著名。'},
  {c:'中国',q:'南方丘陵地区土壤多为红壤，对农业有什么挑战？如何改良？',o:['红壤非常肥沃，无需改良','红壤酸性强、有机质少、板结（透水性差）；改良：施石灰（中和酸性）、施有机肥（提高肥力）、种绿肥','红壤不能种任何植物','只有水分问题'],a:1,e:'南方丘陵红壤改良：①施石灰（降低酸性）②大量施有机肥（腐殖质提高肥力）③种植绿肥（豆科植物固氮）④合理深耕（打破板结层）⑤种植适合酸性土的作物（茶树、柑橘、蓝莓）。'},
  {c:'中国',q:'南方地区洪涝灾害的防治中，恢复洞庭湖和鄱阳湖的蓄洪能力有什么意义？',o:['只是生态价值','湖泊是天然"蓄洪库"，扩大湖容可调蓄长江洪水，减少下游洪灾风险（历史上围湖造田缩小湖面，加剧了1998年洪灾）','减少渔业产量','增加旅游景点'],a:1,e:'恢复湖泊蓄洪功能：洞庭湖（湖南）和鄱阳湖（江西）是长江重要蓄洪湖泊，但50年代以来围湖造田使两湖面积大幅缩小，蓄洪能力下降，1998年长江大洪水教训推动了"退田还湖"政策。'},
  {c:'中国',q:'南方地区的河流与北方相比，水文特征有何不同？',o:['水量更少，含沙量更大','水量大（降水充沛）、含沙量小（植被好）、汛期长（4-10月）、无结冰期；而北方河流水量小，含沙量大（黄河），汛期短，有结冰期','两者完全相同','南方河流季节变化更大'],a:1,e:'南方河流特征（与北方对比）：①水量更大（降水多）②含沙量较少（植被保护好，水土流失轻）③无结冰期（冬季气温>0℃）④汛期长（夏秋季长达6个月以上）。代表：长江、珠江。'},
  {c:'中国',q:'长三角（以上海为中心）发展的优势条件是什么？',o:['煤铁资源丰富','位于长江入海口和沿海交汇处，腹地广阔，交通便利，资金技术雄厚，是中国经济最发达的区域之一','劳动力成本最低','政策优惠最多'],a:1,e:'长三角优势：①地理区位（沿海+长江入海口）②辐射全国（长江流域腹地）③科技人才（顶尖高校+研究机构）④产业链完整⑤国际化程度高（上海是国际金融中心）⑥基础设施完善（高铁、港口）。'},
  {c:'中国',q:'南方地区的"梅雨"是什么天气现象？发生在什么时间？',o:['每年冬季的大雪','每年6-7月长江中下游的持续性阴雨天气（冷暖气流交汇形成准静止锋），空气湿润，易使衣物发霉（"梅雨"或"霉雨"）','秋季的台风带来的降水','夏末的午后雷阵雨'],a:1,e:'梅雨：每年6月中旬至7月上旬，长江中下游地区（上海、南京、武汉附近）受准静止锋影响，出现持续阴雨天气，降水量大，日照少。"梅雨"期间正是梅子成熟季，空气潮湿物品易发霉。'},
  {c:'中国',q:'南方的"伏旱"是什么？发生在哪些地区？',o:['冬季的旱灾','7-8月长江中下游受副热带高气压带控制，晴热高温，降水少，形成旱情（与梅雨相反）；湖南、湖北、江西、安徽等地受影响较重','春季的旱灾','梅雨过后永久不再降雨'],a:1,e:'伏旱：梅雨结束后（约7月中旬），长江中下游受副热带高压控制，盛行下沉气流，高温晴热，形成旱情，影响水稻（双季稻灌浆期）和蔬菜生长。武汉、南京等"三大火炉"城市夏季极其酷热。'}
);

// C8_S2 长江中下游平原（原3题，追加10题）
window.QB_G8_C8_S2.push(
  {c:'中国',q:'长江中下游平原被称为"鱼米之乡"，原因是？',o:['高原地区农业发达','气候温暖湿润，雨热同期，水网密布（湖泊众多），水稻高产，淡水鱼类丰富','干旱少雨，靠灌溉农业','以牧业为主'],a:1,e:'"鱼米之乡"：①气候亚热带季风，雨热同期，水稻一年两熟②湖泊众多（鄱阳湖、洞庭湖、太湖）淡水鱼类极丰富（鲤鱼、鲢鱼等）③低平地形利于农业④人口密集，农业历史悠久。'},
  {c:'中国',q:'太湖是哪个省的重要湖泊？有什么经济意义？',o:['湖南','江苏、浙江、上海交界（以江苏为主）；提供渔业（太湖三白：白鱼、银鱼、白虾）、灌溉、旅游等多种价值','安徽','河南'],a:1,e:'太湖（面积约2338km²）是中国第三大淡水湖，位于江苏南部，周边是长三角核心区（苏锡常+上海）。重要性：①渔业（太湖三白）②水源地③旅游（苏州园林+太湖风光）④近年藻类（蓝藻）污染严重，需综合治理。'},
  {c:'中国',q:'长三角城市群包括哪些城市？在全国经济地位如何？',o:['只有上海一个城市','以上海为核心，包括江苏南京、苏州、杭州、宁波等26个城市；GDP约占全国22%，是中国经济最重要的城市群','只包括上海和南京','包括整个华东所有城市'],a:1,e:'长三角城市群（2016年国家战略）：上海+苏浙皖26个城市，总面积35.8万km²，是中国规模最大、经济最活跃的城市群，GDP约占全国22%。高铁网络密集（上海1小时圈），产业互补，协同发展。'},
  {c:'中国',q:'武汉被称为"九省通衢"，是什么意思？',o:['武汉有9个港口','武汉地处华中，是中国重要的交通枢纽，连接东西南北，公路铁路水运四通八达（京广+汉宜铁路+长江航运）','武汉有9条铁路','武汉出口9种货物'],a:1,e:'"九省通衢"：武汉位于长江和汉江交汇处，华中腹地，是连接东西南北的战略要冲。京广高铁（南北）+武汉城市圈（东西）+长江航运（黄金水道）使武汉成为华中最重要的综合交通枢纽和区域中心城市。'},
  {c:'中国',q:'南京是哪个省的省会？有哪些历史文化特色？',o:['湖北省，无特殊历史','江苏省省会；是中国四大古都之一（六朝古都），有明城墙、中山陵（孙中山陵墓）、夫子庙、秦淮河等著名历史遗迹','浙江省省会','湖南省省会'],a:1,e:'南京（应天府/金陵）：江苏省省会，古代六朝（孙吴、东晋、宋、齐、梁、陈）和明朝、中华民国均在此建都。著名景点：明城墙（世界最长都城城墙）、中山陵、夫子庙-秦淮风光带、玄武湖。'},
  {c:'中国',q:'长江下游地区为何河网密布、湖泊众多？',o:['因为地下有大量水源','地势低平（<50m），地表排水不畅，降水丰富（>1000mm），河流湖泊面积广（江湖交织），历史上长江泥沙冲积形成大量浅水湖泊和湿地','因为是海湾','因为历史上曾是海洋'],a:1,e:'长江中下游湖泊多原因：①地形低平，地表水不易快速排走②降水丰富（梅雨季降水集中）③长江汛期水位高，倒灌湖泊形成大片湿地④历史上古云梦泽等大湖泊（后来淤积分化）。现存：鄱阳湖、洞庭湖、巢湖、太湖等。'},
  {c:'中国',q:'上海为什么能成为中国第一大城市和经济中心？',o:['上海历史最悠久','地理位置优越（长江入海口+沿海）：①扼守长江流域出海口，连接全国最大经济腹地②近代（1842年后）开埠最早，商业金融发达③外资企业聚集④国际贸易港（上海港全球货物吞吐量第一）','上海有煤铁资源','上海人口最少便于管理'],a:1,e:'上海崛起原因：①近代开埠（1843年），引进西方商业模式②长江入海口战略位置——辐射长三角和长江流域（腹地最大）③外资和金融中心（外滩）④浦东开发（1990年起）打造国际金融中心⑤港口（集装箱吞吐量全球第一）。'},
  {c:'中国',q:'长江三角洲地区如何实现"一体化发展"？',o:['各城市独立发展','通过高铁、高速公路网络互联，产业分工协作（上海高端+苏浙制造），共享医疗教育资源，统一环境标准，打破行政壁垒，形成协调一体的城市群','各省竞争资源不合作','只靠市场自然整合'],a:1,e:'长三角一体化：①交通：高铁1小时圈（上海→南京70分钟）②产业：上海（总部经济+金融）+苏南（先进制造）+浙江（数字经济）+安徽（新能源+芯片）③统一环境治理（太湖蓝藻）④异地就医（医保互通）。'},
  {c:'中国',q:'长江中下游平原农业发展面临哪些新挑战？',o:['土地太多，无法管理','城镇化占用耕地（农业用地减少）、农村劳动力向城市流失、农业污染（化肥农药过量）、极端天气（洪涝旱灾频繁）','土地过于肥沃，粮食过剩','全球变暖使该区不适合农业'],a:1,e:'长三角农业挑战：①城镇化快速扩张，农业用地持续减少（珍贵的耕地被建设用地侵占）②青壮年务工进城，农村劳动力老龄化③农业面源污染（化肥、农药、畜禽废水）污染太湖等水体④气候极端化（梅雨增强、夏季高温）。'},
  {c:'中国',q:'洞庭湖在生态和防洪方面的重要性，以及当前面临的主要威胁是什么？',o:['洞庭湖无生态价值','是长江最重要的调蓄湖泊（丰水期蓄洪，枯水期补水）和湿地（候鸟、鱼类栖息地）；威胁：围湖造田（面积缩小60%）、泥沙淤积、水污染','洞庭湖已经干涸','洞庭湖面积在扩大'],a:1,e:'洞庭湖（湖南）：历史上是中国最大淡水湖，现已退居第二（鄱阳湖最大）。重要性：①长江洪水"缓冲区"②珍稀鸟类（麋鹿、江豚）和鱼类栖息地。威胁：围湖造田（1950年代以来面积从4000→2625km²）、上游水土流失带来泥沙淤积。'}
);

// C8_S3 云贵高原（原3题，追加10题）
window.QB_G8_C8_S3.push(
  {c:'中国',q:'云贵高原的地貌最显著特征是什么？形成原因是？',o:['地面平坦，海拔均匀','喀斯特地貌（石灰岩岩溶地貌）：溶洞、石林、峰林、天生桥、地下河；因高原石灰岩广布，水对石灰岩长期溶蚀形成','以沙漠地貌为主','以冰川地貌为主'],a:1,e:'云贵高原喀斯特：石灰岩（CaCO₃）+含CO₂的地下水（H₂CO₃）→溶蚀→溶洞（如桂林，严格说在广西）、石柱（钟乳石）、石林（云南路南石林）、地下河、天坑（重庆武隆）、峰丛（广西）。'},
  {c:'中国',q:'贵州省的著名旅游景观有哪些？',o:['黄山、九寨沟','黄果树瀑布（中国最大瀑布）、荔波喀斯特（世界遗产）、梵净山、万峰林、苗族侗族文化村寨','三峡、峨眉山','张家界、岳阳楼'],a:1,e:'贵州旅游：①黄果树瀑布（珠江支流打帮河上，落差74m，亚洲最大瀑布）②荔波小七孔（世界遗产，喀斯特）③梵净山（世界遗产，黔金丝猴栖息地）④施秉云台山⑤安顺屯堡文化、侗族鼓楼等少数民族文化。'},
  {c:'中国',q:'云南西双版纳有什么独特的自然和文化景观？',o:['以沙漠景观著名','热带雨林（亚洲象、绿孔雀等珍稀动物）+傣族文化（泼水节）；是中国生物多样性最丰富的地区之一','以高原草甸著名','以火山地貌著名'],a:1,e:'西双版纳（云南）：①热带季风气候，热带雨林保存较好②珍稀动物：亚洲象（中国最大野生象群）、绿孔雀、懒猴等③傣族文化：竹楼、泼水节（傣历新年）④澜沧江-湄公河流经，可达东南亚。'},
  {c:'中国',q:'云贵高原为什么有"天气多变，一山分四季"的说法？',o:['高原气候本来多变','高原地形复杂，海拔差异大（山地、盆地、河谷共存），垂直气候带明显（从山脚热带到山顶寒带），以及低纬度+高海拔组合形成多样气候','受台风影响频繁','政策原因'],a:1,e:'"一山分四季，十里不同天"：云贵高原海拔高低差异大（河谷900m，高山4000m+），垂直气候带明显（热带→亚热带→温带→高山寒带），短距离内气候差异极大。云南也因此有"春城"昆明（四季如春，1890m海拔，年均14℃）。'},
  {c:'中国',q:'贵州为什么大数据产业发展迅速？',o:['贵州历史上就是IT中心','气候凉爽（年均气温15℃）、电力充足（水电）、地价低廉，是建设数据中心（服务器需要降温和电力）的理想之地，吸引了腾讯、苹果、华为等数据中心','贵州互联网速度最快','贵州传统工业最发达'],a:1,e:'贵州大数据：2014年国家批准建立"贵州国家大数据综合试验区"。优势：①凉爽气候（自然降温，节能）②大量廉价水电（清洁电力）③土地成本低④远离地震带（安全）。腾讯、苹果、华为数据中心均在贵阳建设。'},
  {c:'中国',q:'云南是中国民族种类最多的省，它的多民族共存有何特点？',o:['各民族分开独立，互不交往','多民族聚居共融，汉族和25个少数民族（彝、白、哈尼、傣、壮、苗等）形成"百里不同风，十里不同俗"的多元文化格局','只有一个少数民族','各民族之间存在严重冲突'],a:1,e:'云南是中国少数民族种类最多省份（26个民族，含汉族），各民族"大杂居小聚居"：滇西北（藏族、纳西族）、滇西（傣族、景颇族）、滇东南（苗族、壮族）各有独特文化，形成世界独一无二的"民族博物馆"。'},
  {c:'中国',q:'云贵高原的农业生产面临哪些主要困难？',o:['气候太好，无困难','地形崎岖（坡地多，耕地破碎，不利于机械化）、水土流失较重、耕地分散（人均耕地少）、部分地区石漠化（岩石裸露）严重','水资源极度缺乏','土壤不含任何营养元素'],a:1,e:'云贵农业困难：①地形崎岖（山地丘陵80%+，平坝耕地少）②坡地耕作水土流失严重③石漠化（喀斯特地区石灰岩裸露，土层极薄，称"地球之疮"）④交通不便（大山阻隔）限制农产品外运。'},
  {c:'中国',q:'昆明被称为"春城"的原因是？',o:['昆明位于热带，全年高温','昆明（云南省省会）海拔约1890m，低纬度（25°N）+高海拔组合，使年均气温约14-15℃，四季如春，无酷暑无严冬','昆明降水最多','昆明冬季最温暖'],a:1,e:'"春城"昆明：低纬度（25°N）决定气温不算太低，高海拔（1890m）决定不会太热，年均14℃，最热月（7月）均温22℃，最冷月（1月）均温7℃，四季如春，是中国少有的"冬无严寒夏无酷暑"城市。'},
  {c:'中国',q:'云南的普洱茶（普洱）产区有何地理条件？',o:['高原寒冷，不适合种茶','北回归线附近，热带亚热带过渡地带，多雾、气候温暖湿润、土壤酸性（红壤）、古茶树资源丰富，是普洱茶的原产地','干旱气候，靠灌溉种茶','低海拔平原地区'],a:1,e:'普洱茶（云南）：澜沧江流域（普洱市、西双版纳、临沧等地），北回归线穿越，热带季风气候，常年多云雾（漫射光利于茶叶品质），酸性砖红壤，有千年以上古茶树（大叶种），是"普洱茶"的地理标志产地。'},
  {c:'中国',q:'石漠化（石漠化=石质荒漠化）在云贵高原的危害是什么？如何治理？',o:['石漠化对当地无危害','导致土壤严重流失（喀斯特基岩裸露）、农业耕地减少、生态系统退化、地下水减少；治理：植树造林（种石生植物）、退耕还林、控制人口、开发石漠化旅游资源','石漠化增加耕地面积','石漠化使土壤更肥沃'],a:1,e:'石漠化（"地球之疮"）：水+石灰岩=溶蚀，土壤流失，基岩裸露，寸草不生。治理：①植树种草（岩溶区适生植物如花椒、椿树）②退耕还林（坡度>25°坡地）③控制人口增长（减少对土地压力）④科学利用石漠化地貌发展旅游。'}
);

// C8_S4 珠三角和香港澳门（原3题，追加10题）
window.QB_G8_C8_S4.push(
  {c:'中国',q:'珠三角经济区发展的主要有利条件有哪些？',o:['煤铁资源最丰富','毗邻香港澳门，对外开放早，吸引大量外资；劳动力充足，珠江水运便利，政策优惠（经济特区）','历史工业基础最雄厚','技术水平最高'],a:1,e:'珠三角发展优势：①毗邻港澳（国际资金技术渠道）②最早对外开放（深圳经济特区1980）③劳动力廉价充足（来自内地）④珠江水运+广州南沙港⑤亚热带气候，农产品丰富⑥政策优惠（外商税收）。'},
  {c:'中国',q:'香港的主要经济支柱是什么？',o:['以农业和采矿为主','国际金融（全球最重要金融中心之一）、贸易（全球最繁忙港口之一）、服务业（占GDP>90%）和航运','以制造业为主','以旅游业为主'],a:1,e:'香港经济：①国际金融中心（全球第三大金融中心，港交所）②自由贸易港（低关税，进出口贸易发达）③国际航运中心（葵涌集装箱港）④旅游（迪士尼乐园）⑤创新科技（初步发展中）。服务业占GDP>90%。'},
  {c:'中国',q:'澳门的主要经济支柱是什么？有何挑战？',o:['以农业为主','以博彩旅游业为主（GDP占比约50%+）；挑战：经济结构过于单一，需多元化发展','以金融业为主','以制造业为主'],a:1,e:'澳门经济以博彩（赌场，合法化）和旅游为主，吸引大量内地和国际游客。挑战：①经济结构单一（高度依赖博彩）②土地面积小（约33km²，人口密度超高）。当前推动旅游+会展+科技等多元化发展。'},
  {c:'中国',q:'粤港澳大湾区是什么？包括哪些城市？',o:['仅香港和澳门组成','由广东9个城市（广州、深圳、珠海、佛山、惠州、东莞、中山、江门、肇庆）+香港+澳门共11个城市组成的世界级湾区','只有广州和深圳','只是广东省城市群'],a:1,e:'粤港澳大湾区（2019年上升为国家战略）：11城市，面积5.6万km²，人口约8600万，GDP约13万亿元，是中国经济最活跃的区域之一，定位：国际科技创新中心、重要港口群和航运枢纽。'},
  {c:'中国',q:'深圳从一个小渔村发展成现代化大都市的主要原因是？',o:['深圳历史悠久，工业基础好','1980年设立经济特区，毗邻香港，实行优惠政策大量吸引外资，改革开放"试验田"，迅速发展','煤铁资源丰富','政府大量直接投资工厂'],a:1,e:'深圳速度：1980年经济特区前是约3万人的小渔村，今已发展为1700万人口的国际化城市（GDP约3.5万亿）。优势：①特区优惠政策（税收减免）②紧邻香港（资金技术）③大量内地廉价劳动力④改革敢闯敢试精神。'},
  {c:'中国',q:'"一国两制"对香港澳门有何意义？',o:['意味着香港澳门独立于中国','1997/1999年回归后实行"一国两制"50年不变：在中华人民共和国主权下，港澳保留原有的资本主义制度和生活方式，高度自治','只有法律制度不同','没有实际意义'],a:1,e:'"一国两制"：邓小平首创，中国主权统一（一国），香港澳门高度自治（两制）：保留资本主义制度（50年）、普通法体系（香港）、港元和澳门元货币、自由港地位。维护了港澳的繁荣稳定和国际地位。'},
  {c:'中国',q:'广州作为千年商都，历史上有何重要地位？',o:['广州是新兴城市，历史不超过百年','广州是中国最早对外贸易港口之一（海上丝绸之路起点）；清朝"一口通商"期间是中国唯一对外贸易港；现为广交会（中国进出口商品交易会）举办地','广州以农业著名','广州以重工业著名'],a:1,e:'广州（广东省省会）：①两千年商业史，古代海上丝绸之路始发港（与泉州并称）②清代一口通商时期是中国唯一外贸港（广州十三行）③广交会（每年两届，全球最大综合性贸易展）④现为华南最大城市和贸易中心。'},
  {c:'中国',q:'珠三角地区产业结构近年来有何变化趋势？',o:['继续发展劳动密集型低端产业','劳动力成本上升，低端产业（制鞋、纺织等）向东南亚和内地转移，珠三角向高附加值产业（电子、汽车、生物医药、人工智能）转型升级','完全放弃制造业','制造业正在消失'],a:1,e:'珠三角产业升级：①30年前以劳动密集型（纺织、玩具、鞋帽）出口为主②现转向高端：华为（通信设备）、比亚迪（新能源汽车）、大疆（无人机）、美的（家电+机器人）等全球知名企业。"中国制造→中国创造"的典型。'},
  {c:'中国',q:'香港是全球重要的航运枢纽，其港口优势体现在哪些方面？',o:['水深无限，无任何限制','维多利亚港天然深水良港、地处太平洋和印度洋航运要冲（马六甲海峡中转）、自由港（低税或零关税）、完善的港口设施','以河运为主','主要用于捕鱼'],a:1,e:'香港港口优势：①维多利亚港：天然深水港（最深约16m），可停靠超大型集装箱船②战略位置：东亚与东南亚、欧洲、美洲航线交汇点③自由港：零关税进出口④专业港口管理（葵涌、青衣集装箱码头）。'},
  {c:'中国',q:'澳门的地理位置特征是什么？对其发展有何影响？',o:['位于中国东北角','位于珠江入海口西侧，与香港隔珠江口相望，毗邻广东珠海，面积极小（约33km²）；地小但战略位置重要，加之博彩业合法化，成为全球最重要旅游博彩中心之一','位于南海中部','位于台湾附近'],a:1,e:'澳门（葡语：Macau）：珠江口西岸，与珠海陆路相连（关闸口岸），港珠澳大桥连接香港（约55km）。面积全国最小（33.3km²）但人口密度极高（每km²约2万人）。经济依托博彩旅游，受地理制约，拓展填海造陆。'}
);

