// 八下·第九章 西北地区
// ─────────────────────────────────────────────

// C9_S1 西北概况（原3题，追加10题）
window.QB_G8_C9_S1.push(
  {c:'中国',q:'西北地区的主要地形特征是？',o:['以平原为主，地势低平','盆地和山地相间（"三山夹两盆"——天山、阿尔泰山、昆仑山/祁连山夹准噶尔盆地和塔里木盆地）','以高原为主','以丘陵为主'],a:1,e:'新疆地形："三山夹两盆"：阿尔泰山（北）夹准噶尔盆地（北疆），天山（中）夹塔里木盆地（南疆），昆仑山-祁连山（南）。这一地形格局决定了南北疆气候、农业的显著差异。'},
  {c:'中国',q:'新疆盛产哈密瓜和葡萄的原因是？',o:['降水充足，水分供应好','气候干旱，昼夜温差大（糖分不被夜间呼吸消耗，积累多），光照充足（有效光合时间长），灌溉农业（坎儿井+雪水）','土壤最肥沃','气温最高'],a:1,e:'吐鲁番瓜果：①温差大（昼夜温差>20℃），夜间低温使有机物（糖分）消耗少，积累多②光照充足（年日照3000小时+）③雪水灌溉（坎儿井）。"吐鲁番的葡萄"含糖量高达18-22%，品质优异。'},
  {c:'中国',q:'西北地区的主要少数民族是？',o:['彝族、壮族','维吾尔族（新疆）、哈萨克族（新疆）、回族（宁夏、甘肃）、蒙古族（内蒙古）','傣族、苗族','藏族、纳西族'],a:1,e:'西北少数民族：①新疆：维吾尔族（最多）、哈萨克族、柯尔克孜族②宁夏、甘肃：回族③内蒙古：蒙古族④甘肃：东乡族、裕固族。各民族有独特的宗教文化（多信仰伊斯兰教）。'},
  {c:'中国',q:'"坎儿井"是新疆特有的引水工程，它的原理是什么？',o:['用水泵抽取地下水','在戈壁滩地下挖掘暗渠，利用地形坡度引导天山雪水在地下流动，最终到达农田；地下渠防止了蒸发，适应干旱气候','用高坝拦蓄河水','用太阳能泵引水'],a:1,e:'坎儿井（新疆古老引水工程）：①在山麓地带开竖井（找地下水）→横向暗渠连接竖井引水→暗渠流向农田的明渠。②全程地下流动防止蒸发（干旱区蒸发极强）③利用地形坡降自流，无需动力。是古代劳动人民的智慧结晶。'},
  {c:'中国',q:'塔克拉玛干沙漠有什么地理特点？',o:['是中国最小的沙漠','是中国最大的沙漠（约33万km²），也是世界第二大流动沙漠，位于塔里木盆地中部，气候极度干旱（年降水<10mm）','降水较多','位于东北地区'],a:1,e:'塔克拉玛干沙漠（维吾尔语意为"进去出不来的地方"）：①面积约33万km²，中国最大②世界第二大流动沙漠（沙丘高达100-200m）③年降水<10mm，极度干旱④吐鲁番最低处（艾丁湖，-154m）在其北缘。'},
  {c:'中国',q:'内蒙古草原的主要生态问题是什么？如何治理？',o:['水土流失','草场退化（过度放牧+气候干旱）和沙化；治理：建立休牧制度、围封禁牧、种植牧草、发展人工草场、减少超载放牧','水资源过多','森林砍伐'],a:1,e:'内蒙古草场退化：①过度放牧（载畜量超过草场承载量）②气候变化（降水减少）③矿产开发破坏草场。治理：草场围栏（防止混牧）→休牧（让草场休养生息）→补播牧草→发展人工草场→推广舍饲圈养减少野外放牧。'},
  {c:'中国',q:'西北地区的能源优势是什么？如何开发利用？',o:['风能和太阳能不足','风能（内蒙古、新疆风力强劲）和太阳能（日照充足）资源极为丰富，以及油气资源（新疆）；通过西电东送和西气东输输往东部','只有石油','只有天然气'],a:1,e:'西北能源：①新疆天然气（塔里木）→西气东输②内蒙古+新疆风电（风力强，风场大）→西电东送③新疆+青海+甘肃光伏（日照充足）→西电东送④新疆石油（克拉玛依）。西北能源基地化是重要战略。'},
  {c:'中国',q:'为什么新疆南北疆（以天山为界）的气候差异显著？',o:['南北纬度差异大','天山山脉阻隔：①北疆（准噶尔）受西风气流和北冰洋气流影响，降水相对较多（200-500mm），冬季积雪厚；②南疆（塔里木）三面环山阻挡水汽，极度干旱（<50mm）','地形完全相同，气候无差异','南疆纬度更高，更寒冷'],a:1,e:'天山是南北疆的气候分界线：①北疆：西风从大西洋带来少量水汽，可穿越准噶尔盆地西部缺口进入，相对湿润，降水100-500mm②南疆：塔里木盆地三面被高山（天山、昆仑山、帕米尔）封闭，水汽进不来，年降水<50mm，极端干旱。'},
  {c:'中国',q:'西北地区为什么是古丝绸之路的重要通道？',o:['西北气候最舒适','连接中国东部与中亚、欧洲的陆上通道（河西走廊→塔里木盆地沿山麓绿洲串联），是古代丝绸、瓷器、香料贸易的主干道，也是文化交流的桥梁','西北全是沙漠，古人不能通行','因为西北有海港'],a:1,e:'丝绸之路（汉代张骞出使西域开拓）：长安（西安）→河西走廊（甘肃）→玉门关/阳关→西域（新疆绿洲城市：敦煌、楼兰、于阗、龟兹）→帕米尔高原→中亚→波斯→罗马。是古代最重要的东西方贸易和文化交流通道。'},
  {c:'中国',q:'敦煌在西北历史地理中有什么重要意义？',o:['是新疆的首府','是古代丝绸之路上的重要咽喉和商贸中心（甘肃西端），以莫高窟（千佛洞）壁画和文物著名，是东西方文化交汇的艺术宝库','是现代工业中心','是西北最大的港口'],a:1,e:'敦煌（甘肃）：古代丝绸之路的战略要地（出玉门关进入西域前的最后重要城市）。莫高窟（世界文化遗产）：735个洞窟，45000多m²壁画，记录了从北凉到元代1000年的佛教艺术和中西文化交流历史，是无价之宝。'}
);

// C9_S2 西北地区的开发（原3题，追加10题）
window.QB_G8_C9_S2.push(
  {c:'中国',q:'西部大开发战略的主要内容有哪些？',o:['只是基础设施建设','基础设施建设（铁路公路管道）、生态保护（退耕还林还草）、资源开发（西气东输西电东送）、引进人才技术、政策优惠','只是吸引外资','只是发展旅游业'],a:1,e:'西部大开发（2000年启动）：①基础设施：青藏铁路、西康铁路、西部公路网②资源开发：西气东输、西电东送③生态：退耕还林、天然林保护④产业：承接东部产业转移⑤人才：优惠政策吸引人才西进。'},
  {c:'中国',q:'"退牧还草"政策的主要目的是？',o:['减少牧业收入','减轻草场压力，让退化草场自然恢复植被（改善生态环境），解决西北内蒙古草场荒漠化问题','发展旅游','将牧民全部移民城市'],a:1,e:'退牧还草：在严重退化草场实行禁牧（全年不放牧）或休牧（季节性禁牧），让草场休养生息。国家对牧民提供补偿（饲料粮）。目标：恢复草场植被，防止荒漠化进一步蔓延，是西北生态修复的核心工程之一。'},
  {c:'中国',q:'新疆发展棉花种植的优势条件有哪些？',o:['降水丰富，无需灌溉','充足日照（年日照2500-3000小时）+昼夜温差大（有利于纤维发育）+降水少（减少病虫害）+机械化程度高（地势平坦）+大量灌溉水源（天山融雪和地下水）','土壤是全国最肥沃的黑土','纬度最低，气温最高'],a:1,e:'新疆棉花优势：①日照充足（纤维光合好）②温差大（纤维粗且长，品质好）③少降水（减少棉铃虫等病虫害）④冲积平原土地平坦（有利于机械采棉）⑤天山融雪水+坎儿井（灌溉水源）。新疆棉花产量占全国85%以上。'},
  {c:'中国',q:'乌鲁木齐是什么城市？有什么地理特征？',o:['新疆自治区首府，有趣地理特征：是世界上距离海洋最远的城市（内陆腹地，距最近海岸约2500km）','甘肃省省会','内蒙古首府','中亚的城市'],a:1,e:'乌鲁木齐（维吾尔语"美丽的牧场"）：新疆维吾尔自治区首府（约400万人），经济和政治中心。地理趣味：是世界上距海洋最远的大城市（距最近海岸约2500km）。天山北麓，准噶尔盆地边缘，气候相对北疆较湿润。'},
  {c:'中国',q:'西北地区土地荒漠化的扩展对中国东部地区有什么影响？',o:['完全无影响','沙尘暴：西北沙漠沙尘被西北风吹向华北（北京等）甚至朝鲜半岛、日本；还影响东部农业（沙化耕地减少粮食产量）','只影响西北本地','增加东部降水'],a:1,e:'西北荒漠化→沙尘暴：每年春季（3-5月）西北强风将沙漠沙尘吹向：内蒙古→华北（北京，PM10暴增）→甚至飘扬过海影响韩国日本。防治：三北防护林（绿色长城）是最重要的防风固沙生态屏障。'},
  {c:'中国',q:'新疆的旅游资源有哪些？',o:['以城市旅游为主','喀纳斯（北疆，秋色绝美）、天山天池、吐鲁番火焰山、塔克拉玛干沙漠、喀什古城（古丝路重镇）、大漠胡杨林等，自然和人文景观极为丰富','只有沙漠景观','只有少数民族文化'],a:1,e:'新疆旅游：①自然：喀纳斯（变色湖，秋天五彩）、天山天池（火山湖，冰雪）、塔克拉玛干（沙海）、胡杨林（轮台，"三千年不死"）②人文：喀什老城（古丝路聚会点）、交河故城（楼兰文化）③民俗：维吾尔族歌舞、手工艺。'},
  {c:'中国',q:'甘肃张掖的"七彩丹霞"是什么地貌？形成原因是什么？',o:['喀斯特地貌','彩色砂岩地貌（丹霞地貌的一种）；由不同地质时期的红、橙、黄、绿、蓝等不同成分沙砾岩层交错，经地壳抬升和长期风化剥蚀后裸露出来','火山地貌','冰川地貌'],a:1,e:'张掖丹霞：由多种颜色的砂岩和泥岩（含不同铁锰矿物）层状堆积，后经地壳隆起、风雨侵蚀、差异剥蚀，形成色彩斑斓的彩色山地，从空中俯视如同一幅画，是中国最美丹霞之一（UNESCO世界地质公园）。'},
  {c:'中国',q:'西北地区发展旅游业面临哪些制约因素？',o:['景观不够吸引人','交通不便（距东部旅客市场遥远，铁路航班有限）、水资源短缺（旅游接待需要水）、环境脆弱（大量游客可能破坏生态）','气候太好旅游者不来','资金不缺'],a:1,e:'西北旅游制约：①距主要客源市场（东部城市）太远，交通成本高②部分地区交通基础设施薄弱③水资源极缺，大量游客难以接待④脆弱生态（沙漠湿地）经不起过度旅游开发。发展"生态旅游"是方向。'},
  {c:'中国',q:'黄河上游流经西北（宁夏、甘肃、内蒙古），对该地区有什么重要意义？',o:['无任何意义','提供重要灌溉水源（宁夏平原、河套平原）；黄河两岸形成了"塞外江南"，是西北农业最发达的地区','造成严重洪涝灾害','是西北地区的主要运输通道'],a:1,e:'黄河上游对西北的意义：①宁夏平原（宁夏银川）：黄河灌溉，沙漠中的绿洲农业，"塞上江南"，盛产水稻枸杞②河套平原（内蒙古）：黄河灌溉，是西北重要粮食产区③水力发电（刘家峡、龙羊峡等梯级水电站）。'},
  {c:'中国',q:'西北地区风能资源丰富，为什么？主要分布在哪里？',o:['西北降水多，带来大量风','西北（内蒙古、新疆、甘肃）植被稀少，地形平坦，摩擦力小，气压梯度大，风力强劲，是中国陆地风能最丰富的地区','只有新疆有风能','只有近海有风能'],a:1,e:'西北风能：①草原戈壁植被稀，摩擦力小②冬季西伯利亚冷气流+蒙古高压驱动②地形平坦（风速均匀）③年平均风速6-8m/s以上。内蒙古（锡林郭勒、乌兰察布）、新疆（达坂城）是中国最重要的风电基地。'}
);

// ─────────────────────────────────────────────
// 八下·第十章 青藏地区
// ─────────────────────────────────────────────

// C10_S1 青藏地区概况（原4题，追加10题）
window.QB_G8_C10_S1.push(
  {c:'中国',q:'青藏高原为什么被称为"世界屋脊"？',o:['因为它是世界上最大的高原','因为平均海拔超过4000m，是世界上海拔最高的高原，站在青藏高原极目远眺，感觉站在世界之巅','因为它最古老','因为它最宽广'],a:1,e:'青藏高原：面积约250万km²，平均海拔4000-5000m，是世界上面积最大、海拔最高的高原。主体在西藏和青海，由欧亚板块与印度洋板块碰撞抬升而成，形成时间约5000万年前开始。'},
  {c:'中国',q:'青藏高原高寒气候的主要特点有哪些？',o:['全年高温，无寒冷','气温低（年均<0℃或略高）、昼夜温差极大（>20℃）、太阳辐射强（紫外线强）、降水少（内陆高原）、风力大','全年多雨','无明显季节变化'],a:1,e:'青藏高寒气候：①年均气温低（拉萨约7℃，但多晴天，日最高可达20℃+）②昼夜温差大（因稀薄大气保温差）③太阳辐射强（海拔高，大气薄，直射强）④内部降水少④大风天数多。'},
  {c:'中国',q:'青藏高原上的居民日常生活有哪些独特之处？（与高寒环境相关）',o:['和平原地区无任何差别','身着厚实藏袍（昼夜温差大，袍可宽可窄），饮酥油茶（高热量，防寒），吃糌粑（青稞面，耐储耐饿），骑牦牛（高原适应），信仰藏传佛教','以水稻为主食','全年穿夏装'],a:1,e:'藏族高寒生活适应：①藏袍（一袍两用，白天腰间系绳，夜晚可披为被）②酥油茶（牦牛黄油+砖茶+盐，热量高御寒）③糌粑（炒青稞面，可干吃，适合游牧携带）④牦牛（毛厚耐寒，提供奶肉皮）。'},
  {c:'中国',q:'青藏高原的农业生产分布在哪里？为什么？',o:['在高原腹地的大面积种植','主要集中在海拔较低的河谷（雅鲁藏布江谷地、湟水谷地），因为河谷海拔低（2000-3000m），气温相对较高（热量较充足），有灌溉水源','在高原顶部（5000m以上）','只靠温室大棚'],a:1,e:'河谷农业：青藏高原上可种植地基本在河谷：①雅鲁藏布江谷地（西藏南部，日喀则等，种青稞、冬小麦）②湟水谷地（青海，西宁附近，种冬小麦、油菜）③大通河谷等。原因：河谷海拔低，气温高2-4℃，是高寒高原的"温暖宝地"。'},
  {c:'中国',q:'拉萨被称为"日光城"，原因是什么？',o:['拉萨全年高温','拉萨海拔约3650m，大气稀薄，云层少，年日照时数达3000小时以上（全国最高之一），阳光充足灿烂','拉萨有太阳能发电站很多','拉萨纬度低日出最早'],a:1,e:'"日光城"拉萨：海拔约3650m，纬度29°N（并不算最低），但大气薄（水汽少，云层少），天空晴朗透明，年日照约3000小时（中国最多地区之一），紫外线极强。布达拉宫的阳光极为灿烂，因此得名。'},
  {c:'中国',q:'布达拉宫在历史上有什么重要地位？现在的保护状态如何？',o:['是现代建筑，建于20世纪','是西藏政教合一统治的中心（历代达赖喇嘛居所兼行政中心），建于7世纪（松赞干布时期），现为世界文化遗产，是西藏历史文化的最重要象征','是一般的寺庙','是中国最新的宫殿'],a:1,e:'布达拉宫（Potala Palace）：7世纪松赞干布为迎娶文成公主修建（今存建筑主要为17世纪重建），位于拉萨红山（海拔3700m），高达13层（约117m），共999间殿堂，是藏传佛教圣地和西藏古代行政中枢，1994年列入UNESCO世界文化遗产。'},
  {c:'中国',q:'三江源（青海）是哪三条江的发源地？其生态意义是什么？',o:['长江、黄河、珠江','长江（通天河段）、黄河、澜沧江（→湄公河）；是"中华水塔"，每年向下游输水约600亿立方米','黄河、淮河、海河','长江、黄河、黑龙江'],a:1,e:'三江源（青海南部）：长江（通天河）、黄河、澜沧江的发源地，有"中华水塔"之称，是全国水量最大的高原湿地。保护三江源生态（2005年建国家级自然保护区）是保障中下游数亿人口水资源的战略行动。'},
  {c:'中国',q:'青藏铁路（格尔木-拉萨段）修建的工程意义是什么？',o:['意义不大，西藏有公路就够了','结束了西藏没有铁路的历史，大幅降低进藏物流成本，促进西藏经济发展，是世界上最高和最长的高原铁路，展示了中国的工程技术实力','只对旅游有意义','是世界上最容易修建的铁路'],a:1,e:'青藏铁路（2006年7月1日通车）：格尔木-拉萨1142km，最高点唐古拉山垭口（5072m，世界铁路最高点）。工程挑战：多年冻土（占全程550km）、高寒缺氧（为工人供氧）、生态保护（设野生动物通道）。通车后进藏货运成本下降约75%。'},
  {c:'中国',q:'青藏高原对全球气候有什么影响？',o:['对全球气候无影响','青藏高原（"第三极"）：①影响东亚和南亚季风环流（高原热力作用）②是亚洲众多大河的发源地（水塔）③高原冰川是气候变化的敏感指示器（冰川融化加速）④隔绝南北气流，影响中国气候格局','只影响西藏本地气候','使全球变暖'],a:1,e:'青藏高原气候影响：①热力作用：夏季是热源，冬季是冷源，影响东亚季风形成和强弱②动力作用：阻挡冬季风南下，使南亚气候不同于同纬度其他地区③水源：亚洲10多条大河发源于此④冰川：储存全球约1/7的淡水，被称为"第三极"。'},
  {c:'中国',q:'青藏地区的矿产资源有哪些优势？',o:['矿产极度贫乏','有色金属（铜、铅锌）、锂（盐湖，全球最大锂资源区之一）、钾盐（柴达木盆地察尔汗盐湖，全国最大钾肥基地）、石油（塔里木、柴达木）','只有盐','只有铁矿'],a:1,e:'青藏矿产：①柴达木盆地（青海）：被称为"聚宝盆"，有钾盐（察尔汗盐湖，中国最大钾肥基地）、石油（冷湖油田）、铅锌、煤等②西藏：铜矿（驱龙，世界级大型铜矿）③盐湖锂资源（供电动汽车电池）是战略性资源。'}
);

// C10_S2 青藏高原的发展（原2题，追加10题）
window.QB_G8_C10_S2.push(
  {c:'中国',q:'青藏高原发展旅游业有哪些优势和限制因素？',o:['只有优势，没有任何限制','优势：独特自然景观（雪山、草甸、湖泊）+藏传佛教文化+稀有动植物；限制：高原反应（低氧）、交通不便、生态脆弱、基础设施薄弱','只有限制因素','发展旅游对生态无任何影响'],a:1,e:'青藏旅游：优势：①珠峰（攀登圣地）②纳木错（世界最高大湖）③雅鲁藏布大峡谷③林芝桃花④布达拉宫。限制：①高原反应（游客需适应期）②旅游基础设施不足③生态极脆弱（游客过多→垃圾环境问题）。'},
  {c:'中国',q:'藏羚羊（藏语"Chiru"）保护的现状和措施是什么？',o:['藏羚羊已经灭绝','20世纪90年代因猎取羊绒（沙图什制品）大规模盗猎，种群数量骤降到约6-8万只；通过禁止捕猎、建立可可西里保护区、打击盗猎，目前恢复到约30万只','藏羚羊不是濒危动物','藏羚羊数量一直很多，无需保护'],a:1,e:'藏羚羊保护：1990年代盗猎猖獗（羊绒=沙图什，价格极高），索南达杰等保护人员以生命守护；1997年可可西里建立国家级自然保护区，2019年列为国家公园。目前种群约30万只，从濒危降为近危。中国反盗猎最著名案例。'},
  {c:'中国',q:'西藏和青海的经济发展方向是什么？',o:['大规模重化工业发展','以生态保护为前提：绿色农牧业（有机牦牛产品）、生态旅游（高质量小规模）、清洁能源（太阳能、水电）、特色文化产业（藏药、藏医、藏族艺术）','大量采矿出口原矿','完全依靠中央财政转移'],a:1,e:'青藏绿色发展：①有机农牧业（高原牦牛、藏系羊，绿色无污染）②生态旅游（限流精品旅游）③清洁能源（太阳能装机量大，雅江水电）④藏药（止血草、红景天等高原药材）⑤生态补偿（保护三江源获得国家补偿）。'},
  {c:'中国',q:'青藏高原冰川融化加速对下游地区有何影响？',o:['对下游无任何影响','短期：冰川融水增加，下游洪水风险增加；长期：冰川持续减少，下游水源减少（中长期水危机），影响亿万人的饮水和灌溉','使下游干旱立即消失','只影响高原本地'],a:1,e:'青藏冰川（储存全球约1/7淡水）融化影响：①近期：融水增多，下游河流夏季洪水增加②长期（50-100年）：冰川大量消融后，夏季融水减少（冰川"过了顶点"），亚洲众多依赖高山融雪的大河（黄河、长江、恒河等）流量减少。'},
  {c:'中国',q:'青藏高原的牦牛对高原生活的适应性表现在哪些方面？',o:['牦牛不适合高原生活','体型大毛发厚实（防寒）、红细胞多（耐低氧）、蹄子宽大（适合高原地形）、耐寒耐粗饲料；为藏民提供奶、肉、皮毛、运输等全方位资源，是"高原之舟"','牦牛只产肉','牦牛不是藏族重要动物'],a:1,e:'牦牛高原适应：①血红蛋白含量是普通牛的3倍（携氧能力强）②厚密毛发（可御-30℃严寒）③蹄宽广（防滑，适合山地碎石）④耐粗饲（吃高原稀疏草）。藏民利用：奶（酥油）、肉、皮（制革）、毛（制袍）、粪（燃料），是高原游牧经济的支柱。'},
  {c:'中国',q:'青藏高原的太阳能资源为什么特别丰富？',o:['因为纬度最低','海拔高（大气稀薄）、晴天多（少云雾）、大气对太阳辐射削弱少，年太阳辐射量居全国第一；拉萨、昌都等地年均日照超3000小时，是发展光伏的绝佳地区','因为气温最高','因为离太阳最近'],a:1,e:'青藏高原太阳能极丰富原因：①海拔高（大气层薄），大气对太阳辐射吸收散射少②云层少（内陆高原，水汽少）③高原面年日照3000-3500小时（全国最多）。中国大型光伏（太阳能电站）大量建设在青海（格尔木）和西藏（拉萨附近）。'},
  {c:'中国',q:'雅鲁藏布江的水能资源有多丰富？已有哪些开发计划？',o:['水能不丰富，不值得开发','雅鲁藏布江大峡谷段（全球最大峡谷）落差达2000多米，水能储量约7000万千瓦，超过三峡；已规划和部分建设多个大型梯级水电站','只有少量水能','已全部开发完毕'],a:1,e:'雅鲁藏布江水能：大峡谷段（直径县至墨脱）落差超2000m，全球最密集水能区。"藏东南水电构想"总装机可达约1亿千瓦（相当于5个三峡），是中国未来最重要的水电开发区。藏木水电站（2014年）已建成，多个梯级站在规划中。'},
  {c:'中国',q:'"高原反应"（高山病）是什么？如何预防？',o:['是一种传染病','因大气含氧量随海拔升高而降低（海拔4000m含氧量约为海平面60%），造成头痛、心跳加速、恶心、气短等症状；预防：初到高原要休息适应，不剧烈运动，必要时吸氧','是由于气温太低导致','是藏族特有的疾病'],a:1,e:'高原反应预防：①初到高原（2500m以上）头2-3天减少活动，充分休息②不饮酒（加重缺氧）③多喝水（预防脱水）④必要时服用高原安等药物⑤严重时吸氧或下撤⑥心肺疾病患者禁止进入高海拔地区。'},
  {c:'中国',q:'为什么说保护青藏高原生态是全国性的大事？',o:['只是地区性问题','青藏高原是亚洲大江大河（长江黄河澜沧江雅鲁藏布江）的发源地（"中华水塔"），保护其植被和冻土可维持水源稳定；高原生态破坏影响下游数亿人口的水资源安全','和内地无关','只影响藏族同胞'],a:1,e:'青藏生态意义：①长江黄河等源区，维护植被=维护水量稳定②高原冻土融化释放CO₂和甲烷（温室气体，加速全球变暖）③高原湿地（三江源）是全球最重要碳汇之一④高原生态崩溃→下游水旱灾害加剧。习近平提出"保护好雪域高原的生灵草木、万水千山"。'},
  {c:'中国',q:'青藏地区的公路建设面临哪些挑战？代表性公路有哪些？',o:['地形平坦，建设容易','多年冻土（路基沉陷）、高寒（施工窗口期短）、高海拔缺氧（施工人员健康）、地质灾害（泥石流、雪崩）；代表：川藏公路（318国道）、青藏公路','只有高原反应一个问题','公路建设已全部完成，无难题'],a:1,e:'青藏公路挑战：①多年冻土（夏季融化路面凹陷，热棒技术处理）②年冻融交替导致路面破损③施工人员高原反应④泥石流/崩塌频发。典型：川藏公路（2000km，最险）；青藏公路（格尔木-拉萨，海拔最高）；新川藏铁路（在建，预计2030年前后建成）。'}
);

